CREATE OR REPLACE FUNCTION "public"."accept_advisor_invitation"("token" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_invitation RECORD;
  v_user_id UUID;
  v_user_email TEXT;
  v_advisor_record RECORD;
BEGIN
  -- Get the current user
  v_user_id := auth.uid();

  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'You must be logged in to accept an invitation');
  END IF;

  -- Get user email
  SELECT email INTO v_user_email FROM auth.users WHERE id = v_user_id;

  -- Find the invitation
  SELECT
    ai.id,
    ai.organization_id,
    ai.advisor_email,
    ai.status,
    ai.expires_at,
    o.name as organization_name
  INTO v_invitation
  FROM advisor_invitations ai
  JOIN organizations o ON o.id = ai.organization_id
  WHERE ai.invitation_token = token::UUID;

  IF v_invitation IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid invitation token');
  END IF;

  -- Check if invitation is still pending
  IF v_invitation.status != 'pending' THEN
    RETURN jsonb_build_object('success', false, 'error', 'This invitation has already been ' || v_invitation.status);
  END IF;

  -- Check if invitation has expired
  IF v_invitation.expires_at < NOW() THEN
    -- Update status to expired
    UPDATE advisor_invitations SET status = 'expired' WHERE id = v_invitation.id;
    RETURN jsonb_build_object('success', false, 'error', 'This invitation has expired');
  END IF;

  -- Check if the logged-in user's email matches the invitation
  IF LOWER(v_user_email) != LOWER(v_invitation.advisor_email) THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'This invitation was sent to ' || v_invitation.advisor_email || '. Please sign in with that account.'
    );
  END IF;

  -- Check if advisor already has access to this organization
  IF EXISTS (
    SELECT 1 FROM advisor_organization_access
    WHERE advisor_user_id = v_user_id
    AND organization_id = v_invitation.organization_id
    AND is_active = true
  ) THEN
    RETURN jsonb_build_object('success', false, 'error', 'You already have advisor access to this organization');
  END IF;

  -- Check if user is already in accredited_advisors, if not add them
  SELECT * INTO v_advisor_record FROM accredited_advisors WHERE user_id = v_user_id;

  IF v_advisor_record IS NULL THEN
    INSERT INTO accredited_advisors (user_id, is_active, accredited_at)
    VALUES (v_user_id, true, NOW());
  END IF;

  -- Grant advisor access to the organization
  INSERT INTO advisor_organization_access (
    advisor_user_id,
    organization_id,
    invitation_id,
    granted_by,
    granted_at,
    is_active
  ) VALUES (
    v_user_id,
    v_invitation.organization_id,
    v_invitation.id,
    (SELECT invited_by FROM advisor_invitations WHERE id = v_invitation.id),
    NOW(),
    true
  )
  ON CONFLICT (advisor_user_id, organization_id)
  DO UPDATE SET
    is_active = true,
    granted_at = NOW(),
    revoked_at = NULL,
    revoked_by = NULL,
    revocation_reason = NULL;

  -- Update the invitation status
  UPDATE advisor_invitations
  SET
    status = 'accepted',
    accepted_at = NOW()
  WHERE id = v_invitation.id;

  RETURN jsonb_build_object(
    'success', true,
    'organization_id', v_invitation.organization_id,
    'organization_name', v_invitation.organization_name
  );
END;
$$;


ALTER FUNCTION "public"."accept_advisor_invitation"("token" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."accept_supplier_invitation"("p_token" "text", "p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_invitation record;
  v_supplier_id uuid;
  v_platform_supplier_id uuid;
  v_user_email text;
BEGIN
  -- Get and validate invitation (lock row to prevent race conditions)
  SELECT * INTO v_invitation
  FROM public.supplier_invitations
  WHERE invitation_token = p_token
    AND status = 'pending'
    AND expires_at > now()
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid or expired invitation');
  END IF;

  -- Get user email for verification
  SELECT email INTO v_user_email
  FROM auth.users WHERE id = p_user_id;

  IF v_user_email IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;

  -- Check email matches invitation
  IF lower(v_user_email) != lower(v_invitation.supplier_email) THEN
    RETURN jsonb_build_object('success', false, 'error', 'Email does not match invitation');
  END IF;

  -- Resolve the supplier record, in priority order.
  -- (a) Invitation already points at a supplier record (e.g. one the brand
  --     auto-created when sending an ESG survey). Adopt it.
  IF v_invitation.supplier_id IS NOT NULL THEN
    v_supplier_id := v_invitation.supplier_id;
    UPDATE public.suppliers
    SET user_id = COALESCE(user_id, p_user_id),
        contact_name = COALESCE(contact_name, v_invitation.contact_person_name)
    WHERE id = v_supplier_id;
  END IF;

  -- (b) This user already has a supplier record in this org.
  IF v_supplier_id IS NULL THEN
    SELECT id INTO v_supplier_id
    FROM public.suppliers
    WHERE user_id = p_user_id
      AND organization_id = v_invitation.organization_id;
  END IF;

  -- (c) An org-scoped record exists for this email but has no user yet
  --     (brand created it at send time). Adopt it.
  IF v_supplier_id IS NULL THEN
    SELECT id INTO v_supplier_id
    FROM public.suppliers
    WHERE organization_id = v_invitation.organization_id
      AND user_id IS NULL
      AND lower(contact_email) = lower(v_invitation.supplier_email)
    ORDER BY created_at
    LIMIT 1;

    IF v_supplier_id IS NOT NULL THEN
      UPDATE public.suppliers
      SET user_id = p_user_id,
          contact_name = COALESCE(contact_name, v_invitation.contact_person_name)
      WHERE id = v_supplier_id;
    END IF;
  END IF;

  -- (d) Nothing to adopt — create a fresh record.
  IF v_supplier_id IS NULL THEN
    INSERT INTO public.suppliers (
      organization_id, name, contact_email, contact_name, user_id
    ) VALUES (
      v_invitation.organization_id,
      COALESCE(v_invitation.supplier_name, 'Unnamed Supplier'),
      v_invitation.supplier_email,
      v_invitation.contact_person_name,
      p_user_id
    )
    RETURNING id INTO v_supplier_id;
  END IF;

  -- Create or find platform_suppliers record (with user_id so the admin portal
  -- can locate the account).
  SELECT id INTO v_platform_supplier_id
  FROM public.platform_suppliers
  WHERE lower(contact_email) = lower(v_invitation.supplier_email);

  IF v_platform_supplier_id IS NULL THEN
    INSERT INTO public.platform_suppliers (
      name, contact_email, contact_name, is_verified, user_id
    ) VALUES (
      COALESCE(v_invitation.supplier_name, 'Unnamed Supplier'),
      v_invitation.supplier_email,
      v_invitation.contact_person_name,
      false,
      p_user_id
    )
    ON CONFLICT DO NOTHING
    RETURNING id INTO v_platform_supplier_id;
  ELSE
    UPDATE public.platform_suppliers
    SET user_id = p_user_id
    WHERE id = v_platform_supplier_id AND user_id IS NULL;
  END IF;

  -- Link the organization to the platform supplier. If the link already exists
  -- (e.g. created with status 'invited' when the brand sent the survey), promote
  -- it to 'active' so the brand's supplier list reflects that the supplier joined.
  IF v_platform_supplier_id IS NOT NULL THEN
    INSERT INTO public.organization_suppliers (
      organization_id, platform_supplier_id, engagement_status
    ) VALUES (
      v_invitation.organization_id, v_platform_supplier_id, 'active'
    )
    ON CONFLICT (organization_id, platform_supplier_id)
    DO UPDATE SET engagement_status = 'active';
  END IF;

  -- SECURITY: Do NOT add suppliers to organization_members.
  DELETE FROM public.organization_members
  WHERE organization_id = v_invitation.organization_id
    AND user_id = p_user_id;

  -- Create or activate engagement record (a record may already exist from
  -- send time with status 'invited').
  INSERT INTO public.supplier_engagements (
    supplier_id, status, invited_date, accepted_date
  ) VALUES (
    v_supplier_id, 'active', v_invitation.invited_at::date, now()::date
  )
  ON CONFLICT (supplier_id) DO UPDATE SET
    status = 'active',
    accepted_date = COALESCE(public.supplier_engagements.accepted_date, now()::date);

  -- Mark invitation as accepted
  UPDATE public.supplier_invitations
  SET status = 'accepted',
      accepted_at = now(),
      supplier_id = v_supplier_id
  WHERE id = v_invitation.id;

  RETURN jsonb_build_object(
    'success', true,
    'supplier_id', v_supplier_id,
    'organization_id', v_invitation.organization_id
  );
END;
$$;


ALTER FUNCTION "public"."accept_supplier_invitation"("p_token" "text", "p_user_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."accept_supplier_invitation"("p_token" "text", "p_user_id" "uuid") IS 'Accepts a supplier invitation: adopts any pre-created supplier record (or creates one), links the platform directory entry, org link, and engagement. Removes any org membership to keep suppliers isolated.';



CREATE OR REPLACE FUNCTION "public"."add_user_to_platform_admin"("target_user_email" "text") RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
v_user_id uuid;
v_platform_org_id uuid;
v_profile_name text;
BEGIN
SELECT au.id, p.full_name
INTO v_user_id, v_profile_name
FROM auth.users au
LEFT JOIN profiles p ON p.id = au.id
WHERE au.email = target_user_email;

IF v_user_id IS NULL THEN
RAISE EXCEPTION 'User with email % not found', target_user_email;
END IF;

SELECT id INTO v_platform_org_id
FROM organizations
WHERE is_platform_admin = true
LIMIT 1;

IF v_platform_org_id IS NULL THEN
RAISE EXCEPTION 'No platform admin organization found';
END IF;

INSERT INTO organization_members (organization_id, user_id, role)
VALUES (v_platform_org_id, v_user_id, 'admin')
ON CONFLICT (organization_id, user_id) DO NOTHING;

RETURN json_build_object(
'success', true,
'user_id', v_user_id,
'user_email', target_user_email,
'user_name', v_profile_name,
'organization_id', v_platform_org_id,
'message', 'User added to platform admin organization'
);
END;
$$;


ALTER FUNCTION "public"."add_user_to_platform_admin"("target_user_email" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."approve_pending_activity_data"("p_pending_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
pending_record RECORD;
new_record_id UUID;
BEGIN
IF NOT can_approve_data() THEN
RAISE EXCEPTION 'Permission denied: User cannot approve data';
END IF;

SELECT * INTO pending_record
FROM public.pending_activity_data
WHERE id = p_pending_id
AND organization_id = get_current_organization_id()
AND approval_status = 'pending';

IF NOT FOUND THEN
RAISE EXCEPTION 'Pending record not found or already processed';
END IF;

INSERT INTO public.activity_data (
organization_id, user_id, name, category, quantity, unit, activity_date
) VALUES (
pending_record.organization_id,
pending_record.submitted_by,
pending_record.name,
pending_record.category,
pending_record.quantity,
pending_record.unit,
pending_record.activity_date
)
RETURNING id INTO new_record_id;

UPDATE public.pending_activity_data
SET approval_status = 'approved',
reviewed_by = auth.uid(),
reviewed_at = now(),
original_id = new_record_id
WHERE id = p_pending_id;

PERFORM create_notification(
pending_record.submitted_by,
pending_record.organization_id,
'approval',
'Data Approved',
'Your activity data submission "' || pending_record.name || '" has been approved.',
'activity_data',
new_record_id::text
);

PERFORM log_platform_activity('data_approved', 'approval_workflow');

RETURN new_record_id;
END;
$$;


ALTER FUNCTION "public"."approve_pending_activity_data"("p_pending_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."approve_pending_activity_data"("p_pending_id" "uuid") IS 'Approve pending activity data and copy to main table';



