CREATE OR REPLACE FUNCTION "public"."check_facility_limit"("p_organization_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_tier text;
  v_status text;
  v_max_facilities int;
  v_current_count int;
BEGIN
  SELECT subscription_tier, subscription_status
  INTO v_tier, v_status
  FROM organizations
  WHERE id = p_organization_id;

  IF v_tier IS NULL THEN
    RETURN jsonb_build_object(
      'allowed', false,
      'reason', 'Organisation not found',
      'current_count', 0,
      'max_count', 0,
      'tier', 'seed',
      'is_unlimited', false
    );
  END IF;

  IF v_status NOT IN ('active', 'trial', 'pending', 'past_due') THEN
    RETURN jsonb_build_object(
      'allowed', false,
      'reason', 'Subscription is not active',
      'current_count', 0,
      'max_count', 0,
      'tier', v_tier,
      'is_unlimited', false
    );
  END IF;

  SELECT max_facilities INTO v_max_facilities
  FROM subscription_tier_limits
  WHERE tier_name = v_tier AND is_active = true;

  SELECT count(*) INTO v_current_count
  FROM facilities
  WHERE organization_id = p_organization_id;

  IF v_max_facilities IS NULL THEN
    RETURN jsonb_build_object(
      'allowed', true,
      'reason', NULL,
      'current_count', v_current_count,
      'max_count', NULL,
      'tier', v_tier,
      'is_unlimited', true
    );
  END IF;

  IF v_current_count >= v_max_facilities THEN
    RETURN jsonb_build_object(
      'allowed', false,
      'reason', format('Facility limit reached (%s/%s). Upgrade to add more facilities.', v_current_count, v_max_facilities),
      'current_count', v_current_count,
      'max_count', v_max_facilities,
      'tier', v_tier,
      'is_unlimited', false
    );
  END IF;

  RETURN jsonb_build_object(
    'allowed', true,
    'reason', NULL,
    'current_count', v_current_count,
    'max_count', v_max_facilities,
    'tier', v_tier,
    'is_unlimited', false
  );
END;
$$;


ALTER FUNCTION "public"."check_facility_limit"("p_organization_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_feature_access"("p_organization_id" "uuid", "p_feature_code" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_tier TEXT;
  v_status TEXT;
  v_has_feature BOOLEAN;
BEGIN
  -- Get organization tier and status
  SELECT subscription_tier, subscription_status
  INTO v_tier, v_status
  FROM public.organizations
  WHERE id = p_organization_id;

  IF v_tier IS NULL THEN
    RETURN jsonb_build_object(
      'allowed', false,
      'reason', 'Organization not found'
    );
  END IF;

  -- Check subscription status - allow active, trial, AND past_due (grace period)
  IF v_status NOT IN ('active', 'trial', 'past_due') THEN
    RETURN jsonb_build_object(
      'allowed', false,
      'reason', 'Subscription is ' || v_status,
      'tier', v_tier
    );
  END IF;

  -- Check if feature is enabled for this tier
  SELECT EXISTS(
    SELECT 1 FROM public.subscription_tier_limits
    WHERE tier = v_tier
    AND p_feature_code = ANY(features_enabled)
  ) INTO v_has_feature;

  -- Also check org-level feature flags (admin overrides)
  IF NOT v_has_feature THEN
    SELECT COALESCE(
      (feature_flags->>p_feature_code)::boolean,
      false
    )
    INTO v_has_feature
    FROM public.organizations
    WHERE id = p_organization_id;
  END IF;

  RETURN jsonb_build_object(
    'allowed', v_has_feature,
    'reason', CASE WHEN v_has_feature THEN 'Feature available' ELSE 'Feature not available on ' || v_tier || ' tier' END,
    'tier', v_tier,
    'feature', p_feature_code
  );
END;
$$;


ALTER FUNCTION "public"."check_feature_access"("p_organization_id" "uuid", "p_feature_code" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_lca_limit"("p_organization_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_tier text;
  v_status text;
  v_current_count integer;
  v_max_count integer;
  v_can_create boolean;
BEGIN
  SELECT subscription_tier, subscription_status
  INTO v_tier, v_status
  FROM public.organizations
  WHERE id = p_organization_id;

  IF v_tier IS NULL THEN
    RETURN jsonb_build_object(
      'allowed', false,
      'reason', 'Organization not found',
      'current_count', 0,
      'max_count', 0,
      'tier', 'seed',
      'is_unlimited', false
    );
  END IF;

  -- Allow active, trial, pending (new onboarding), and past_due (grace period)
  IF v_status NOT IN ('active', 'trial', 'pending', 'past_due') THEN
    RETURN jsonb_build_object(
      'allowed', false,
      'reason', 'Subscription is ' || v_status,
      'current_count', 0,
      'max_count', 0,
      'tier', v_tier,
      'is_unlimited', false
    );
  END IF;

  -- Live count from actual LCAs table
  SELECT COUNT(*) INTO v_current_count
  FROM public.product_carbon_footprints
  WHERE organization_id = p_organization_id;

  SELECT max_lcas INTO v_max_count
  FROM public.subscription_tier_limits
  WHERE tier_name = v_tier;

  v_can_create := v_max_count IS NULL OR v_current_count < v_max_count;

  RETURN jsonb_build_object(
    'allowed', v_can_create,
    'reason', CASE
      WHEN v_can_create THEN null
      ELSE 'LCA limit reached (' || v_current_count || '/' || v_max_count || '). Upgrade to create more LCAs.'
    END,
    'current_count', v_current_count,
    'max_count', v_max_count,
    'tier', v_tier,
    'is_unlimited', v_max_count IS NULL
  );
END;
$$;


ALTER FUNCTION "public"."check_lca_limit"("p_organization_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_methodology_access"("p_organization_id" "uuid", "p_methodology" "text") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_tier text;
  v_status text;
  v_has_access boolean;
BEGIN
  SELECT subscription_tier, subscription_status
  INTO v_tier, v_status
  FROM public.organizations
  WHERE id = p_organization_id;

  IF v_tier IS NULL THEN
    RETURN false;
  END IF;

  IF v_status NOT IN ('active', 'trial', 'pending', 'past_due') THEN
    RETURN false;
  END IF;

  SELECT enabled INTO v_has_access
  FROM public.subscription_tier_features
  WHERE tier_name = v_tier
  AND feature_code = p_methodology;

  RETURN COALESCE(v_has_access, false);
END;
$$;


