CREATE OR REPLACE FUNCTION "public"."check_report_limit"("p_organization_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_tier text;
  v_status text;
  v_current_count integer;
  v_max_count integer;
  v_can_generate boolean;
BEGIN
  SELECT subscription_tier, subscription_status
  INTO v_tier, v_status
  FROM public.organizations
  WHERE id = p_organization_id;

  IF v_tier IS NULL THEN
    RETURN jsonb_build_object(
      'allowed', false,
      'reason', 'Organization not found',
      'current_count', 0,
      'max_count', 0,
      'tier', 'seed',
      'is_unlimited', false
    );
  END IF;

  IF v_status NOT IN ('active', 'trial', 'pending', 'past_due') THEN
    RETURN jsonb_build_object(
      'allowed', false,
      'reason', 'Subscription is ' || v_status,
      'current_count', 0,
      'max_count', 0,
      'tier', v_tier,
      'is_unlimited', false
    );
  END IF;

  -- Live count from product_carbon_footprints + generated_reports created this month
  SELECT
    (SELECT COUNT(*) FROM public.product_carbon_footprints
     WHERE organization_id = p_organization_id
       AND created_at >= date_trunc('month', now()))
    +
    (SELECT COUNT(*) FROM public.generated_reports
     WHERE organization_id = p_organization_id
       AND created_at >= date_trunc('month', now()))
  INTO v_current_count;

  SELECT max_reports_per_month INTO v_max_count
  FROM public.subscription_tier_limits
  WHERE tier_name = v_tier;

  v_can_generate := v_max_count IS NULL OR v_current_count < v_max_count;

  RETURN jsonb_build_object(
    'allowed', v_can_generate,
    'reason', CASE
      WHEN v_can_generate THEN null
      ELSE 'Monthly report limit reached (' || v_current_count || '/' || v_max_count || '). Upgrade for more reports.'
    END,
    'current_count', v_current_count,
    'max_count', v_max_count,
    'tier', v_tier,
    'is_unlimited', v_max_count IS NULL,
    'resets_at', date_trunc('month', now()) + interval '1 month'
  );
END;
$$;


ALTER FUNCTION "public"."check_report_limit"("p_organization_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_supplier_limit"("p_organization_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_tier text;
  v_status text;
  v_max_suppliers int;
  v_current_count int;
BEGIN
  SELECT subscription_tier, subscription_status
  INTO v_tier, v_status
  FROM organizations
  WHERE id = p_organization_id;

  IF v_tier IS NULL THEN
    RETURN jsonb_build_object(
      'allowed', false,
      'reason', 'Organisation not found',
      'current_count', 0,
      'max_count', 0,
      'tier', 'seed',
      'is_unlimited', false
    );
  END IF;

  IF v_status NOT IN ('active', 'trial', 'pending', 'past_due') THEN
    RETURN jsonb_build_object(
      'allowed', false,
      'reason', 'Subscription is not active',
      'current_count', 0,
      'max_count', 0,
      'tier', v_tier,
      'is_unlimited', false
    );
  END IF;

  SELECT max_suppliers INTO v_max_suppliers
  FROM subscription_tier_limits
  WHERE tier_name = v_tier AND is_active = true;

  SELECT count(*) INTO v_current_count
  FROM suppliers
  WHERE organization_id = p_organization_id;

  IF v_max_suppliers IS NULL THEN
    RETURN jsonb_build_object(
      'allowed', true,
      'reason', NULL,
      'current_count', v_current_count,
      'max_count', NULL,
      'tier', v_tier,
      'is_unlimited', true
    );
  END IF;

  IF v_current_count >= v_max_suppliers THEN
    RETURN jsonb_build_object(
      'allowed', false,
      'reason', format('Supplier limit reached (%s/%s). Upgrade to add more suppliers.', v_current_count, v_max_suppliers),
      'current_count', v_current_count,
      'max_count', v_max_suppliers,
      'tier', v_tier,
      'is_unlimited', false
    );
  END IF;

  RETURN jsonb_build_object(
    'allowed', true,
    'reason', NULL,
    'current_count', v_current_count,
    'max_count', v_max_suppliers,
    'tier', v_tier,
    'is_unlimited', false
  );
END;
$$;


ALTER FUNCTION "public"."check_supplier_limit"("p_organization_id" "uuid") OWNER TO "postgres";


