CREATE OR REPLACE FUNCTION "public"."find_similar_organizations"("brand_name" "text", "similarity_threshold" double precision DEFAULT 0.6) RETURNS TABLE("id" "uuid", "name" "text", "website" "text", "similarity" double precision)
    LANGUAGE "sql" STABLE
