CREATE OR REPLACE FUNCTION "public"."get_brand_data_for_distributor"("p_brand_directory_id" "uuid", "p_distributor_org_id" "uuid", "p_brand_sku_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("field_key" "text", "field_value" "text", "field_value_numeric" numeric, "source" "text", "confidence" numeric, "scraped_at" timestamp with time zone, "brand_sku_id" "uuid")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_alkatera_org_id uuid;
  v_link_active boolean := false;
begin
  return query
  select sbd.field_key, sbd.field_value, sbd.field_value_numeric,
         sbd.source_name, sbd.confidence, sbd.scraped_at, sbd.brand_sku_id
  from public.scraped_brand_data sbd
  where sbd.brand_directory_id = p_brand_directory_id
    and sbd.superseded_by is null
    and sbd.brand_sku_id is null
    and (
      sbd.source_name <> 'brand_verified'
      or not exists (
        select 1
        from public.brand_directory bd
        join public.brand_sharing_preferences pref
          on pref.alkatera_org_id = bd.alkatera_org_id
        where bd.id = p_brand_directory_id
          and bd.alkatera_org_id is not null
          and (pref.distributor_org_id is null
               or pref.distributor_org_id = p_distributor_org_id)
          and (
            pref.block_all_fields = true
            or (pref.field_key = sbd.field_key and pref.sharing_enabled = false)
          )
      )
    );

  if p_brand_sku_id is not null then
    return query
    select sbd.field_key, sbd.field_value, sbd.field_value_numeric,
           sbd.source_name, sbd.confidence, sbd.scraped_at, sbd.brand_sku_id
    from public.scraped_brand_data sbd
    where sbd.brand_directory_id = p_brand_directory_id
      and sbd.brand_sku_id = p_brand_sku_id
      and sbd.superseded_by is null
      and (
        sbd.source_name <> 'brand_verified'
        or not exists (
          select 1
          from public.brand_directory bd
          join public.brand_sharing_preferences pref
            on pref.alkatera_org_id = bd.alkatera_org_id
          where bd.id = p_brand_directory_id
            and bd.alkatera_org_id is not null
            and (pref.distributor_org_id is null
                 or pref.distributor_org_id = p_distributor_org_id)
            and (
              pref.block_all_fields = true
              or (pref.field_key = sbd.field_key and pref.sharing_enabled = false)
            )
        )
      );
  end if;

  select bd.alkatera_org_id into v_alkatera_org_id
  from public.brand_directory bd
  where bd.id = p_brand_directory_id;
  if v_alkatera_org_id is null then return; end if;

  select true into v_link_active
  from public.brand_distributor_links bdl
  where bdl.alkatera_org_id = v_alkatera_org_id
    and bdl.distributor_org_id = p_distributor_org_id
    and bdl.sharing_active = true
    and bdl.confirmed_by_brand = true
  limit 1;
  if not coalesce(v_link_active, false) then return; end if;

  return query
  select alk.field_key, alk.field_value, alk.field_value_numeric,
         'alkatera_live'::text, 0.99::numeric, alk.scraped_at, alk.brand_sku_id
  from public.scraped_brand_data alk
  where alk.brand_directory_id = p_brand_directory_id
    and alk.source_name = 'alkatera_live'
    and alk.superseded_by is null
    and (p_brand_sku_id is null or alk.brand_sku_id is null or alk.brand_sku_id = p_brand_sku_id)
    and not exists (
      select 1
      from public.brand_sharing_preferences pref
      where pref.alkatera_org_id = v_alkatera_org_id
        and (pref.distributor_org_id is null
             or pref.distributor_org_id = p_distributor_org_id)
        and (
          pref.block_all_fields = true
          or (pref.field_key = alk.field_key and pref.sharing_enabled = false)
        )
    );
end;
$$;


ALTER FUNCTION "public"."get_brand_data_for_distributor"("p_brand_directory_id" "uuid", "p_distributor_org_id" "uuid", "p_brand_sku_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_brand_data_for_procurement"("p_procurement_org_id" "uuid", "p_brand_directory_id" "uuid") RETURNS TABLE("field_key" "text", "field_value" "text", "field_value_numeric" numeric, "source" "text", "confidence" numeric, "scraped_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if not public.procurement_has_access_to_brand(p_procurement_org_id, p_brand_directory_id) then
    return;
  end if;

  return query
  select sbd.field_key,
         sbd.field_value,
         sbd.field_value_numeric,
         sbd.source_name,
         sbd.confidence,
         sbd.scraped_at
  from public.scraped_brand_data sbd
  where sbd.brand_directory_id = p_brand_directory_id
    and sbd.superseded_by is null
    and sbd.brand_sku_id is null
    and (
      sbd.source_name not in ('brand_verified', 'alkatera_live')
      or not exists (
        select 1
        from public.brand_directory bd
        join public.brand_sharing_preferences pref
          on pref.alkatera_org_id = bd.alkatera_org_id
        where bd.id = p_brand_directory_id
          and bd.alkatera_org_id is not null
          and (
            pref.distributor_org_id is null
            or pref.distributor_org_id in (
              select pdl.distributor_org_id
              from public.procurement_distributor_links pdl
              where pdl.procurement_org_id = p_procurement_org_id
                and pdl.status = 'active'
            )
          )
          and (
            pref.block_all_fields = true
            or (pref.field_key = sbd.field_key and pref.sharing_enabled = false)
          )
      )
    );
end;
$$;


ALTER FUNCTION "public"."get_brand_data_for_procurement"("p_procurement_org_id" "uuid", "p_brand_directory_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_combined_emissions_by_scope"("p_organization_id" "uuid", "p_reporting_year" integer, "p_scope" "text" DEFAULT NULL::"text") RETURNS TABLE("scope" "text", "total_tco2e" numeric, "source_type" "text", "entry_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
RETURN QUERY
SELECT 
'Scope 1'::TEXT as scope,
COALESCE(SUM(fa.emissions_tco2e), 0)::NUMERIC as total_tco2e,
'fleet'::TEXT as source_type,
COUNT(*)::BIGINT as entry_count
FROM fleet_activities fa
WHERE fa.organization_id = p_organization_id
AND EXTRACT(YEAR FROM COALESCE(fa.reporting_period_start, fa.activity_date)) = p_reporting_year
AND fa.scope = 'Scope 1'
AND (p_scope IS NULL OR fa.scope = p_scope)
GROUP BY fa.scope

UNION ALL

SELECT 
'Scope 2'::TEXT as scope,
COALESCE(SUM(fa.emissions_tco2e), 0)::NUMERIC as total_tco2e,
'fleet'::TEXT as source_type,
COUNT(*)::BIGINT as entry_count
FROM fleet_activities fa
WHERE fa.organization_id = p_organization_id
AND EXTRACT(YEAR FROM COALESCE(fa.reporting_period_start, fa.activity_date)) = p_reporting_year
AND fa.scope = 'Scope 2'
AND (p_scope IS NULL OR fa.scope = p_scope)
GROUP BY fa.scope

UNION ALL

SELECT 
'Scope 3 Cat 6'::TEXT as scope,
COALESCE(SUM(fa.emissions_tco2e), 0)::NUMERIC as total_tco2e,
'fleet'::TEXT as source_type,
COUNT(*)::BIGINT as entry_count
FROM fleet_activities fa
WHERE fa.organization_id = p_organization_id
AND EXTRACT(YEAR FROM COALESCE(fa.reporting_period_start, fa.activity_date)) = p_reporting_year
AND fa.scope = 'Scope 3 Cat 6'
AND (p_scope IS NULL OR fa.scope = p_scope)
GROUP BY fa.scope;
END;
$$;


ALTER FUNCTION "public"."get_combined_emissions_by_scope"("p_organization_id" "uuid", "p_reporting_year" integer, "p_scope" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_combined_emissions_by_scope"("p_organization_id" "uuid", "p_reporting_year" integer, "p_scope" "text") IS 'Aggregates fleet emissions by scope for use in corporate carbon footprint reports. 
Returns emissions from the standalone fleet_activities table only.';



CREATE OR REPLACE FUNCTION "public"."get_current_organization_id"() RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE claims jsonb; claimed uuid;
BEGIN
  claims := current_setting('request.jwt.claims', true)::jsonb;
  claimed := nullif(coalesce(claims -> 'app_metadata' ->> 'current_organization_id', claims -> 'user_metadata' ->> 'current_organization_id'), '')::uuid;
  IF claimed IS NULL THEN RETURN NULL; END IF;
  IF public.user_has_organization_access(claimed) THEN RETURN claimed; END IF;
  RETURN NULL;
EXCEPTION WHEN OTHERS THEN RETURN NULL;
END; $$;


ALTER FUNCTION "public"."get_current_organization_id"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_current_organization_id"() IS 'Returns the organization_id for the currently authenticated user. This is the single source of truth for all multi-tenancy RLS checks. Uses SECURITY DEFINER to bypass RLS and prevent recursion. Returns NULL if user is not a member of any organization.';



CREATE OR REPLACE FUNCTION "public"."get_default_dashboard_layout"() RETURNS TABLE("widget_id" "text", "widget_enabled" boolean, "widget_order" integer, "widget_col_span" integer, "widget_row_span" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
BEGIN
RETURN QUERY
SELECT 
dw.id,
true,
dw.sort_order,
CASE dw.default_size
WHEN 'compact' THEN 1
WHEN 'standard' THEN 2
WHEN 'expanded' THEN 4
ELSE 2
END,
1
FROM dashboard_widgets dw
WHERE dw.is_active = true
ORDER BY dw.sort_order;
END;
$$;


