COMMENT ON FUNCTION "public"."get_ingredient_audit_summary"("p_lca_id" "uuid") IS 'Calculates data quality metrics for an LCA based on ingredient selections';



CREATE OR REPLACE FUNCTION "public"."get_my_organization_role"("org_id" "uuid") RETURNS "public"."organization_role"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  role_name text;
  org_role organization_role;
BEGIN
  SELECT r.name INTO role_name
  FROM organization_members om
  JOIN roles r ON om.role_id = r.id
  WHERE om.organization_id = org_id
    AND om.user_id = auth.uid();

  IF role_name IN ('owner', 'admin') THEN
    org_role := 'company_admin';
  ELSIF role_name IN ('member', 'viewer') THEN
    org_role := 'company_user';
  ELSE
    org_role := NULL;
  END IF;

  RETURN org_role;
END;
$$;


ALTER FUNCTION "public"."get_my_organization_role"("org_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_my_organization_role_id"("org_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  role_uuid uuid;
BEGIN
  SELECT om.role_id INTO role_uuid
  FROM organization_members om
  WHERE om.organization_id = org_id
    AND om.user_id = auth.uid();

  RETURN role_uuid;
END;
$$;


ALTER FUNCTION "public"."get_my_organization_role_id"("org_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_next_recalculation_job"() RETURNS TABLE("queue_id" "uuid", "product_lca_id" "uuid", "organization_id" "uuid", "batch_id" "uuid", "attempt_count" integer)
    LANGUAGE "plpgsql"
    AS $$
DECLARE
v_job RECORD;
BEGIN
SELECT 
q.id,
q.product_lca_id,
q.organization_id,
q.batch_id,
q.attempt_count
INTO v_job
FROM public.lca_recalculation_queue q
WHERE q.status = 'pending'
AND (q.next_retry_at IS NULL OR q.next_retry_at <= now())
ORDER BY q.priority DESC, q.created_at ASC
LIMIT 1
FOR UPDATE SKIP LOCKED;

IF v_job IS NULL THEN
RETURN;
END IF;

UPDATE public.lca_recalculation_queue
SET 
status = 'processing',
processing_started_at = now(),
attempt_count = attempt_count + 1,
updated_at = now()
WHERE id = v_job.id;

UPDATE public.product_lcas
SET ef31_recalculation_status = 'processing'
WHERE id = v_job.product_lca_id;

RETURN QUERY SELECT 
v_job.id,
v_job.product_lca_id,
v_job.organization_id,
v_job.batch_id,
v_job.attempt_count + 1;
END;
$$;


ALTER FUNCTION "public"."get_next_recalculation_job"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_next_recalculation_job"() IS 'Atomically claims and returns the next pending recalculation job from the queue.';



CREATE OR REPLACE FUNCTION "public"."get_onboarding_analytics"() RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  result JSONB;
  v_total_orgs INTEGER;
  v_with_onboarding INTEGER;
  v_completed INTEGER;
  v_dismissed INTEGER;
  v_in_progress INTEGER;
  v_trial_count INTEGER;
  v_paid_count INTEGER;
BEGIN
  IF NOT is_alkatera_admin() THEN
    RETURN jsonb_build_object('error', 'Unauthorized');
  END IF;

  -- Total non-platform-admin orgs
  SELECT COUNT(*) INTO v_total_orgs
  FROM organizations WHERE is_platform_admin != true;

  -- Orgs with onboarding records
  SELECT COUNT(*) INTO v_with_onboarding
  FROM onboarding_state;

  -- Completed
  SELECT COUNT(*) INTO v_completed
  FROM onboarding_state
  WHERE (state->>'completed')::boolean = true;

  -- Dismissed (not completed)
  SELECT COUNT(*) INTO v_dismissed
  FROM onboarding_state
  WHERE (state->>'dismissed')::boolean = true
    AND ((state->>'completed')::boolean IS NULL OR (state->>'completed')::boolean = false);

  -- In progress
  v_in_progress := GREATEST(v_with_onboarding - v_completed - v_dismissed, 0);

  -- Trial vs paid conversion
  SELECT COUNT(*) INTO v_trial_count
  FROM organizations
  WHERE subscription_status = 'trial' AND is_platform_admin != true;

  SELECT COUNT(*) INTO v_paid_count
  FROM organizations
  WHERE subscription_status = 'active'
    AND stripe_subscription_id IS NOT NULL
    AND is_platform_admin != true;

  SELECT jsonb_build_object(
    'total_orgs', v_total_orgs,
    'with_onboarding', v_with_onboarding,
    'completed', v_completed,
    'dismissed', v_dismissed,
    'in_progress', v_in_progress,
    'completion_rate', CASE WHEN v_with_onboarding > 0
      THEN ROUND(v_completed::numeric / v_with_onboarding * 100, 1)
      ELSE 0 END,
    'phases', jsonb_build_object(
      'welcome', (SELECT COUNT(*) FROM onboarding_state
        WHERE state->'completedSteps' ? 'welcome-screen'),
      'quick_wins', (SELECT COUNT(*) FROM onboarding_state
        WHERE state->'completedSteps' ? 'roadmap'),
      'core_setup', (SELECT COUNT(*) FROM onboarding_state
        WHERE state->'completedSteps' ? 'facilities-setup'),
      'first_insights', (SELECT COUNT(*) FROM onboarding_state
        WHERE state->'completedSteps' ? 'foundation-complete'),
      'power_features', (SELECT COUNT(*) FROM onboarding_state
        WHERE state->'completedSteps' ? 'feature-showcase')
    ),
    'conversion', jsonb_build_object(
      'trial_count', v_trial_count,
      'paid_count', v_paid_count,
      'conversion_rate', CASE WHEN (v_trial_count + v_paid_count) > 0
        THEN ROUND(v_paid_count::numeric / (v_trial_count + v_paid_count) * 100, 1)
        ELSE 0 END
    ),
    'avg_completion_days', (
      SELECT ROUND(AVG(
        EXTRACT(EPOCH FROM (
          (state->>'completedAt')::timestamptz - (state->>'startedAt')::timestamptz
        )) / 86400
      )::numeric, 1)
      FROM onboarding_state
      WHERE (state->>'completed')::boolean = true
        AND state->>'completedAt' IS NOT NULL
        AND state->>'startedAt' IS NOT NULL
    )
  ) INTO result;

  RETURN result;
END;
$$;


ALTER FUNCTION "public"."get_onboarding_analytics"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."get_onboarding_analytics"() IS 'Returns onboarding funnel analytics: completion rates, phase drop-off, trial-to-paid conversion, and average completion time.';



CREATE OR REPLACE FUNCTION "public"."get_organization_advisors"("p_org_id" "uuid") RETURNS TABLE("advisor_user_id" "uuid", "advisor_email" "text", "advisor_name" "text", "company_name" "text", "expertise_areas" "text"[], "granted_at" timestamp with time zone, "is_active" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Check if caller has access to this organization
  IF NOT EXISTS (
    SELECT 1 FROM organization_members om
    JOIN roles r ON r.id = om.role_id
    WHERE om.organization_id = p_org_id
    AND om.user_id = auth.uid()
    AND r.name IN ('owner', 'admin')
  ) THEN
    RAISE EXCEPTION 'Access denied: You must be an owner or admin of this organization';
  END IF;

  RETURN QUERY
  SELECT
    aoa.advisor_user_id,
    u.email::TEXT as advisor_email,
    p.full_name::TEXT as advisor_name,
    aa.company_name::TEXT,
    aa.expertise_areas,
    aoa.granted_at,
    aoa.is_active
  FROM advisor_organization_access aoa
  JOIN auth.users u ON u.id = aoa.advisor_user_id
  LEFT JOIN profiles p ON p.id = aoa.advisor_user_id
  LEFT JOIN accredited_advisors aa ON aa.user_id = aoa.advisor_user_id
  WHERE aoa.organization_id = p_org_id
  ORDER BY aoa.is_active DESC, aoa.granted_at DESC;
END;
$$;


ALTER FUNCTION "public"."get_organization_advisors"("p_org_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_organization_benchmark_comparison"("p_organization_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
v_result jsonb;
v_latest_score organization_vitality_scores%ROWTYPE;
v_platform_benchmark vitality_benchmarks%ROWTYPE;
v_category_benchmark vitality_benchmarks%ROWTYPE;
v_org_category text;
BEGIN
IF NOT EXISTS (
SELECT 1 FROM organization_members
WHERE organization_id = p_organization_id
AND user_id = auth.uid()
) THEN
RAISE EXCEPTION 'Access denied';
END IF;

SELECT * INTO v_latest_score
FROM organization_vitality_scores
WHERE organization_id = p_organization_id
ORDER BY calculation_date DESC
LIMIT 1;

IF NOT FOUND THEN
RETURN jsonb_build_object(
'has_data', false,
'message', 'No vitality scores calculated yet'
);
END IF;

SELECT industry_sector INTO v_org_category
FROM organizations
WHERE id = p_organization_id;

SELECT * INTO v_platform_benchmark
FROM vitality_benchmarks
WHERE benchmark_type = 'platform';

IF v_org_category IS NOT NULL THEN
SELECT * INTO v_category_benchmark
FROM vitality_benchmarks
WHERE benchmark_type = 'category'
AND category_name = v_org_category;
END IF;

v_result := jsonb_build_object(
'has_data', true,
'current_scores', jsonb_build_object(
'overall', v_latest_score.overall_score,
'climate', v_latest_score.climate_score,
'water', v_latest_score.water_score,
'circularity', v_latest_score.circularity_score,
'nature', v_latest_score.nature_score,
'calculation_date', v_latest_score.calculation_date
),
'platform_benchmarks', jsonb_build_object(
'overall_average', v_platform_benchmark.overall_avg,
'climate_average', v_platform_benchmark.climate_avg,
'water_average', v_platform_benchmark.water_avg,
'circularity_average', v_platform_benchmark.circularity_avg,
'nature_average', v_platform_benchmark.nature_avg,
'overall_top', v_platform_benchmark.overall_top,
'climate_top', v_platform_benchmark.climate_top,
'water_top', v_platform_benchmark.water_top,
'circularity_top', v_platform_benchmark.circularity_top,
'nature_top', v_platform_benchmark.nature_top,
'organization_count', v_platform_benchmark.organization_count
)
);

IF v_category_benchmark IS NOT NULL THEN
v_result := v_result || jsonb_build_object(
'category_benchmarks', jsonb_build_object(
'category_name', v_org_category,
'overall_average', v_category_benchmark.overall_avg,
'climate_average', v_category_benchmark.climate_avg,
'water_average', v_category_benchmark.water_avg,
'circularity_average', v_category_benchmark.circularity_avg,
'nature_average', v_category_benchmark.nature_avg,
'overall_top', v_category_benchmark.overall_top,
'climate_top', v_category_benchmark.climate_top,
'water_top', v_category_benchmark.water_top,
'circularity_top', v_category_benchmark.circularity_top,
'nature_top', v_category_benchmark.nature_top,
'organization_count', v_category_benchmark.organization_count
)
);
END IF;

RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."get_organization_benchmark_comparison"("p_organization_id" "uuid") OWNER TO "postgres";


