CREATE OR REPLACE FUNCTION "public"."get_supplier_invitations"("p_status" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "material_name" "text", "material_type" "text", "request_kind" "text", "status" "public"."supplier_invitation_status", "invited_at" timestamp with time zone, "accepted_at" timestamp with time zone, "organization_name" "text", "request_status" "text", "request_responded_at" timestamp with time zone, "request_decline_reason" "text", "personal_message" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    si.id,
    COALESCE(si.material_name, 'General invitation') AS material_name,
    COALESCE(si.material_type, 'general') AS material_type,
    si.request_kind,
    si.status,
    si.invited_at,
    si.accepted_at,
    o.name AS organization_name,
    si.request_status,
    si.request_responded_at,
    si.request_decline_reason,
    si.personal_message
  FROM public.supplier_invitations si
  JOIN public.organizations o ON o.id = si.organization_id
  WHERE (
    si.supplier_id IN (
      SELECT s.id FROM public.suppliers s WHERE s.user_id = auth.uid()
    )
    OR (
      si.supplier_id IS NULL
      AND lower(si.supplier_email) = lower(
        (SELECT email FROM auth.users WHERE auth.users.id = auth.uid())
      )
    )
  )
  AND (p_status IS NULL OR si.status::text = p_status)
  ORDER BY si.invited_at DESC;
END;
$$;


