CREATE OR REPLACE FUNCTION "public"."handle_new_user"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_organization_id UUID;
  v_role_id UUID;
BEGIN
  -- Create the profile
  INSERT INTO public.profiles (id, email, full_name, avatar_url)
  VALUES (
    NEW.id,
    NEW.email,
    NEW.raw_user_meta_data->>'full_name',
    NEW.raw_user_meta_data->>'avatar_url'
  );

  -- Check if this user was invited to an organization
  v_organization_id := (NEW.raw_user_meta_data->>'organization_id')::UUID;
  v_role_id := (NEW.raw_user_meta_data->>'role_id')::UUID;

  -- If invitation metadata exists, add them to the organization
  IF v_organization_id IS NOT NULL AND v_role_id IS NOT NULL THEN
    INSERT INTO public.organization_members (
      organization_id,
      user_id,
      role_id,
      joined_at
    )
    VALUES (
      v_organization_id,
      NEW.id,
      v_role_id,
      NOW()
    )
    ON CONFLICT (organization_id, user_id) DO NOTHING;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_new_user"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."has_permission"("permission_name" "text", "org_id" "uuid" DEFAULT NULL::"uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
DECLARE
target_org_id uuid;
BEGIN
IF org_id IS NOT NULL THEN
target_org_id := org_id;
ELSE
target_org_id := get_current_organization_id();
END IF;

IF target_org_id IS NULL THEN
RETURN false;
END IF;

RETURN EXISTS (
SELECT 1
FROM organization_members om
JOIN role_permissions rp ON om.role_id = rp.role_id
JOIN permissions p ON rp.permission_id = p.id
WHERE om.user_id = auth.uid()
AND om.organization_id = target_org_id
AND p.name = permission_name
);
END;
$$;


