CREATE OR REPLACE FUNCTION "public"."match_alkatera_org"("query_name" "text", "similarity_threshold" double precision DEFAULT 0.85) RETURNS TABLE("id" "uuid", "name" "text", "similarity" double precision, "match_via" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with q as (
    select public.brand_directory_normalize(query_name) as norm
  )
  select
    o.id,
    o.name,
    case
      when public.brand_directory_normalize(o.name) = q.norm then 1.0::float
      else similarity(public.brand_directory_normalize(o.name), q.norm)
    end as similarity,
    case
      when public.brand_directory_normalize(o.name) = q.norm then 'exact_name'
      else 'fuzzy'
    end as match_via
  from public.organizations o
  cross join q
  where q.norm <> ''
    and o.name is not null
    and (
      public.brand_directory_normalize(o.name) = q.norm
      or similarity(public.brand_directory_normalize(o.name), q.norm)
         >= similarity_threshold
    )
  order by similarity desc, o.created_at asc
  limit 5;
$$;


ALTER FUNCTION "public"."match_alkatera_org"("query_name" "text", "similarity_threshold" double precision) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."match_brand_directory"("query_name" "text", "similarity_threshold" double precision DEFAULT 0.85) RETURNS TABLE("id" "uuid", "name" "text", "normalized_name" "text", "alkatera_org_id" "uuid", "similarity" double precision, "match_via" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with q as (
    select public.brand_directory_normalize(query_name) as norm
  )
  select
    bd.id, bd.name, bd.normalized_name, bd.alkatera_org_id,
    case
      when bd.normalized_name = q.norm then 1.0::float
      when q.norm = any(bd.aliases) then 1.0::float
      else similarity(bd.normalized_name, q.norm)
    end as similarity,
    case
      when bd.normalized_name = q.norm then 'exact_name'
      when q.norm = any(bd.aliases) then 'alias'
      else 'fuzzy'
    end as match_via
  from public.brand_directory bd
  cross join q
  where q.norm <> ''
    and (
      bd.normalized_name = q.norm
      or q.norm = any(bd.aliases)
      or similarity(bd.normalized_name, q.norm) >= similarity_threshold
    )
  order by
    similarity desc,
    case when bd.alkatera_org_id is not null then 0 else 1 end,
    bd.created_at asc
  limit 5;
$$;


ALTER FUNCTION "public"."match_brand_directory"("query_name" "text", "similarity_threshold" double precision) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."match_product_directory"("p_brand_directory_id" "uuid", "p_query_name" "text", "p_gtin" "text" DEFAULT NULL::"text", "p_similarity_threshold" double precision DEFAULT 0.85) RETURNS TABLE("id" "uuid", "name" "text", "normalized_name" "text", "gtin" "text", "alkatera_product_id" "uuid", "similarity" double precision, "match_via" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with q as (
    select public.product_directory_normalize(p_query_name) as norm,
           nullif(trim(coalesce(p_gtin, '')), '') as gtin_clean
  )
  select pd.id, pd.name, pd.normalized_name, pd.gtin, pd.alkatera_product_id,
    case
      when q.gtin_clean is not null and pd.gtin = q.gtin_clean then 1.0::float
      when pd.normalized_name = q.norm then 1.0::float
      else similarity(pd.normalized_name, q.norm)
    end as similarity,
    case
      when q.gtin_clean is not null and pd.gtin = q.gtin_clean then 'gtin'
      when pd.normalized_name = q.norm then 'exact_name'
      else 'fuzzy'
    end as match_via
  from public.product_directory pd cross join q
  where pd.brand_directory_id = p_brand_directory_id
    and (
      (q.gtin_clean is not null and pd.gtin = q.gtin_clean)
      or (q.norm <> '' and pd.normalized_name = q.norm)
      or (q.norm <> '' and similarity(pd.normalized_name, q.norm) >= p_similarity_threshold)
    )
  order by similarity desc, pd.created_at asc limit 5;
$$;


ALTER FUNCTION "public"."match_product_directory"("p_brand_directory_id" "uuid", "p_query_name" "text", "p_gtin" "text", "p_similarity_threshold" double precision) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."merge_brand_directory_dupe"("p_canonical_id" "uuid", "p_dupe_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_canonical_name        text;
  v_canonical_org         uuid;
  v_canonical_aliases     text[];
  v_dupe_name             text;
  v_dupe_org              uuid;
  v_dupe_aliases          text[];
begin
  if p_canonical_id = p_dupe_id then
    raise exception 'merge_dupe: canonical and dupe must differ';
  end if;

  select name, alkatera_org_id, aliases
    into v_canonical_name, v_canonical_org, v_canonical_aliases
  from public.brand_directory where id = p_canonical_id;
  if not found then
    raise exception 'merge_dupe: canonical % not found', p_canonical_id;
  end if;

  select name, alkatera_org_id, aliases
    into v_dupe_name, v_dupe_org, v_dupe_aliases
  from public.brand_directory where id = p_dupe_id;
  if not found then
    raise exception 'merge_dupe: dupe % not found', p_dupe_id;
  end if;

  if v_canonical_org is not null and v_dupe_org is not null
     and v_canonical_org <> v_dupe_org then
    raise exception 'merge_dupe: both rows are alkatera-linked to different orgs (% vs %)',
      v_canonical_org, v_dupe_org;
  end if;

  delete from public.brand_profiles bp_dupe
  where bp_dupe.brand_directory_id = p_dupe_id
    and exists (
      select 1 from public.brand_profiles bp_canon
      where bp_canon.brand_directory_id = p_canonical_id
        and bp_canon.distributor_org_id = bp_dupe.distributor_org_id
    );
  update public.brand_profiles
    set brand_directory_id = p_canonical_id, updated_at = now()
    where brand_directory_id = p_dupe_id;

  delete from public.product_directory pd_dupe
  where pd_dupe.brand_directory_id = p_dupe_id
    and pd_dupe.gtin is not null
    and exists (
      select 1 from public.product_directory pd_canon
      where pd_canon.brand_directory_id = p_canonical_id
        and pd_canon.gtin = pd_dupe.gtin
    );
  update public.product_directory
    set brand_directory_id = p_canonical_id, updated_at = now()
    where brand_directory_id = p_dupe_id;

  update public.scraped_brand_data
    set brand_directory_id = p_canonical_id
    where brand_directory_id = p_dupe_id;

  update public.brand_document_submissions
    set brand_directory_id = p_canonical_id
    where brand_directory_id = p_dupe_id;

  update public.brand_data_conflicts
    set brand_directory_id = p_canonical_id
    where brand_directory_id = p_dupe_id;

  update public.brand_completeness_snapshots
    set brand_directory_id = p_canonical_id
    where brand_directory_id = p_dupe_id;

  update public.scraping_jobs
    set brand_directory_id = p_canonical_id
    where brand_directory_id = p_dupe_id;

  update public.directory_brand_views
    set brand_directory_id = p_canonical_id
    where brand_directory_id = p_dupe_id;
  update public.directory_contacts
    set brand_directory_id = p_canonical_id
    where brand_directory_id = p_dupe_id;

  declare
    v_new_aliases text[] := coalesce(v_canonical_aliases, array[]::text[]);
    v_existing_lower text[] :=
      coalesce(
        array(select lower(unnest(v_canonical_aliases))),
        array[]::text[]
      );
    v_candidate text;
  begin
    if v_dupe_name is not null
       and lower(v_dupe_name) <> lower(v_canonical_name)
       and not (lower(v_dupe_name) = any(v_existing_lower))
    then
      v_new_aliases := v_new_aliases || array[v_dupe_name];
      v_existing_lower := v_existing_lower || array[lower(v_dupe_name)];
    end if;
    if v_dupe_aliases is not null then
      foreach v_candidate in array v_dupe_aliases loop
        if lower(v_candidate) <> lower(v_canonical_name)
           and not (lower(v_candidate) = any(v_existing_lower))
        then
          v_new_aliases := v_new_aliases || array[v_candidate];
          v_existing_lower := v_existing_lower || array[lower(v_candidate)];
        end if;
      end loop;
    end if;
    if array_length(v_new_aliases, 1) is distinct from
       array_length(coalesce(v_canonical_aliases, array[]::text[]), 1) then
      update public.brand_directory
        set aliases = v_new_aliases, updated_at = now()
        where id = p_canonical_id;
    end if;
  end;

  delete from public.brand_directory where id = p_dupe_id;
end;
$$;


ALTER FUNCTION "public"."merge_brand_directory_dupe"("p_canonical_id" "uuid", "p_dupe_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."merge_product_directory_dupe"("p_canonical_id" "uuid", "p_dupe_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_canonical_brand uuid;
  v_canonical_name  text;
  v_canonical_gtin  text;
  v_dupe_brand      uuid;
  v_dupe_name       text;
  v_dupe_gtin       text;
begin
  if p_canonical_id = p_dupe_id then
    raise exception 'merge_product_dupe: canonical and dupe must differ';
  end if;

  select brand_directory_id, name, gtin
    into v_canonical_brand, v_canonical_name, v_canonical_gtin
  from public.product_directory where id = p_canonical_id;
  if not found then
    raise exception 'merge_product_dupe: canonical % not found', p_canonical_id;
  end if;

  select brand_directory_id, name, gtin
    into v_dupe_brand, v_dupe_name, v_dupe_gtin
  from public.product_directory where id = p_dupe_id;
  if not found then
    raise exception 'merge_product_dupe: dupe % not found', p_dupe_id;
  end if;

  if v_canonical_brand <> v_dupe_brand then
    raise exception 'merge_product_dupe: rows belong to different brands (% vs %)',
      v_canonical_brand, v_dupe_brand;
  end if;

  update public.brand_skus
    set product_directory_id = p_canonical_id, updated_at = now()
    where product_directory_id = p_dupe_id;

  update public.scraped_brand_data
    set product_directory_id = p_canonical_id
    where product_directory_id = p_dupe_id;

  update public.brand_document_submissions
    set product_directory_ids = (
      select coalesce(
        array_agg(distinct case when v = p_dupe_id then p_canonical_id else v end),
        '{}'::uuid[]
      )
      from unnest(product_directory_ids) as v
    )
    where p_dupe_id = any(product_directory_ids);

  if v_canonical_gtin is null and v_dupe_gtin is not null then
    update public.product_directory
      set gtin = v_dupe_gtin, updated_at = now()
      where id = p_canonical_id;
    update public.product_directory
      set gtin = null
      where id = p_dupe_id;
  end if;

  delete from public.product_directory where id = p_dupe_id;
end;
$$;


ALTER FUNCTION "public"."merge_product_directory_dupe"("p_canonical_id" "uuid", "p_dupe_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."notify_advisor_message"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  conv_record RECORD;
  sender_name TEXT;
  recipient_id UUID;
BEGIN
  -- Get conversation info
  SELECT * INTO conv_record
  FROM public.advisor_conversations
  WHERE id = NEW.conversation_id;

  -- Get sender name
  SELECT COALESCE(full_name, email) INTO sender_name
  FROM public.profiles
  WHERE id = NEW.sender_id;

  -- Determine recipient: if sender is the advisor, notify org members; if sender is org member, notify advisor
  IF NEW.sender_id = conv_record.advisor_user_id THEN
    -- Advisor sent message → notify all org members
    INSERT INTO public.user_notifications (
      user_id, organization_id, notification_type,
      title, message, entity_type, entity_id, metadata
    )
    SELECT
      om.user_id,
      conv_record.organization_id,
      'advisor_message',
      'Message from advisor ' || COALESCE(sender_name, 'Advisor'),
      LEFT(NEW.message, 100),
      'advisor_conversation',
      conv_record.id::text,
      jsonb_build_object('message_id', NEW.id, 'sender_id', NEW.sender_id)
    FROM public.organization_members om
    WHERE om.organization_id = conv_record.organization_id
      AND om.user_id != NEW.sender_id;
  ELSE
    -- Org member sent message → notify the advisor
    INSERT INTO public.user_notifications (
      user_id, organization_id, notification_type,
      title, message, entity_type, entity_id, metadata
    ) VALUES (
      conv_record.advisor_user_id,
      conv_record.organization_id,
      'advisor_message',
      'Message from ' || COALESCE(sender_name, 'User'),
      LEFT(NEW.message, 100),
      'advisor_conversation',
      conv_record.id::text,
      jsonb_build_object('message_id', NEW.id, 'sender_id', NEW.sender_id)
    );
  END IF;

  -- Update conversation last_message_at
  UPDATE public.advisor_conversations
  SET last_message_at = now(), updated_at = now()
  WHERE id = NEW.conversation_id;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_advisor_message"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."notify_feedback_message"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  ticket_record RECORD;
  sender_name TEXT;
BEGIN
  -- Get ticket info
  SELECT * INTO ticket_record
  FROM public.feedback_tickets
  WHERE id = NEW.ticket_id;

  -- Get sender name
  SELECT COALESCE(full_name, email) INTO sender_name
  FROM public.profiles
  WHERE id = NEW.sender_id;

  IF NEW.is_admin_reply THEN
    -- Notify the ticket creator that admin replied
    INSERT INTO public.user_notifications (
      user_id,
      organization_id,
      notification_type,
      title,
      message,
      entity_type,
      entity_id,
      metadata
    ) VALUES (
      ticket_record.created_by,
      ticket_record.organization_id,
      'feedback_reply',
      'Reply to your ' || ticket_record.category || ' report',
      'Alkatera support responded to "' || ticket_record.title || '"',
      'feedback_ticket',
      ticket_record.id,
      jsonb_build_object('message_id', NEW.id)
    );
  ELSE
    -- Notify admins of new user message
    INSERT INTO public.user_notifications (
      user_id,
      organization_id,
      notification_type,
      title,
      message,
      entity_type,
      entity_id,
      metadata
    )
    SELECT
      p.id,
      ticket_record.organization_id,
      'feedback_message',
      'New message on ticket: ' || ticket_record.title,
      COALESCE(sender_name, 'User') || ' sent a message',
      'feedback_ticket',
      ticket_record.id,
      jsonb_build_object('message_id', NEW.id)
    FROM public.profiles p
    WHERE p.is_alkatera_admin = true;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_feedback_message"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."notify_new_feedback_ticket"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  admin_ids UUID[];
  admin_id UUID;
  submitter_name TEXT;
BEGIN
  -- Get submitter name
  SELECT COALESCE(full_name, email) INTO submitter_name
  FROM public.profiles
  WHERE id = NEW.created_by;

  -- Get all Alkatera admins
  SELECT ARRAY_AGG(id) INTO admin_ids
  FROM public.profiles
  WHERE is_alkatera_admin = true;

  -- Create notification for each admin
  IF admin_ids IS NOT NULL THEN
    FOREACH admin_id IN ARRAY admin_ids
    LOOP
      INSERT INTO public.user_notifications (
        user_id,
        organization_id,
        notification_type,
        title,
        message,
        entity_type,
        entity_id,
        metadata
      ) VALUES (
        admin_id,
        NEW.organization_id,
        'feedback_ticket',
        'New ' || NEW.category || ' report: ' || NEW.title,
        COALESCE(submitter_name, 'A user') || ' submitted a new ' || NEW.category || ' report',
        'feedback_ticket',
        NEW.id,
        jsonb_build_object('category', NEW.category, 'priority', NEW.priority)
      );
    END LOOP;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_new_feedback_ticket"() OWNER TO "postgres";


