CREATE OR REPLACE FUNCTION "public"."prevent_supplier_org_membership"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF EXISTS (
    SELECT 1 FROM public.suppliers
    WHERE user_id = NEW.user_id
      AND organization_id = NEW.organization_id
  ) THEN
    RAISE EXCEPTION 'Suppliers cannot be added to organization_members. User % is a supplier for org %.', NEW.user_id, NEW.organization_id;
  END IF;
  RETURN NEW;
END;
$$;


