COMMENT ON TABLE "public"."epr_audit_log" IS 'Immutable, append-only audit trail for all EPR compliance data changes. Required for 7-year data retention under EPR regulations.';



COMMENT ON COLUMN "public"."epr_audit_log"."field_changes" IS 'Granular diff of changed fields: { "field_name": { "old": <previous_value>, "new": <new_value> } }';



COMMENT ON COLUMN "public"."epr_audit_log"."snapshot" IS 'Complete entity state at the time of the change. Used for point-in-time reconstruction during audits.';



