CREATE TABLE IF NOT EXISTS "public"."epr_prn_obligations" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "organization_id" "uuid" NOT NULL,
    "obligation_year" integer NOT NULL,
    "material_code" "text" NOT NULL,
    "material_name" "text" NOT NULL,
    "total_tonnage_placed" numeric DEFAULT 0 NOT NULL,
    "recycling_target_pct" numeric NOT NULL,
    "obligation_tonnage" numeric DEFAULT 0 NOT NULL,
    "prns_purchased_tonnage" numeric DEFAULT 0 NOT NULL,
    "prn_cost_per_tonne_gbp" numeric DEFAULT 0,
    "total_prn_cost_gbp" numeric DEFAULT 0 NOT NULL,
    "status" "text" DEFAULT 'not_started'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "epr_prn_obligations_status_check" CHECK (("status" = ANY (ARRAY['not_started'::"text", 'partial'::"text", 'fulfilled'::"text", 'exceeded'::"text"])))
);


ALTER TABLE "public"."epr_prn_obligations" OWNER TO "postgres";


COMMENT ON TABLE "public"."epr_prn_obligations" IS 'Per-organisation PRN obligation tracking. Large producers must purchase PRNs/PERNs for each material to meet recycling targets.';



COMMENT ON COLUMN "public"."epr_prn_obligations"."obligation_tonnage" IS 'Calculated as total_tonnage_placed × recycling_target_pct / 100. This is the tonnage of PRNs/PERNs that must be acquired.';



CREATE TABLE IF NOT EXISTS "public"."epr_prn_targets" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "obligation_year" integer NOT NULL,
    "material_code" "text" NOT NULL,
    "material_name" "text" NOT NULL,
    "recycling_target_pct" numeric NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "epr_prn_targets_recycling_target_pct_check" CHECK ((("recycling_target_pct" > (0)::numeric) AND ("recycling_target_pct" <= (100)::numeric)))
);


ALTER TABLE "public"."epr_prn_targets" OWNER TO "postgres";


COMMENT ON TABLE "public"."epr_prn_targets" IS 'PRN recycling targets published annually by government. Used to calculate per-material obligation tonnage.';



CREATE TABLE IF NOT EXISTS "public"."epr_submission_lines" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "submission_id" "uuid" NOT NULL,
    "organization_id" "uuid" NOT NULL,
    "product_id" bigint,
    "product_name" "text",
    "product_material_id" bigint,
    "rpd_organisation_id" "text" NOT NULL,
    "rpd_subsidiary_id" "text",
    "rpd_organisation_size" "text" NOT NULL,
    "rpd_submission_period" "text" NOT NULL,
    "rpd_packaging_activity" "text" NOT NULL,
    "rpd_packaging_type" "text" NOT NULL,
    "rpd_packaging_class" "text" NOT NULL,
    "rpd_packaging_material" "text" NOT NULL,
    "rpd_material_subtype" "text",
    "rpd_from_nation" "text" NOT NULL,
    "rpd_to_nation" "text",
    "rpd_material_weight_kg" numeric NOT NULL,
    "rpd_material_units" integer,
    "rpd_transitional_weight" numeric,
    "rpd_recyclability_rating" "text",
    "fee_rate_per_tonne" numeric,
    "estimated_fee_gbp" numeric DEFAULT 0 NOT NULL,
    "is_drs_excluded" boolean DEFAULT false NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "epr_submission_lines_rpd_from_nation_check" CHECK (("rpd_from_nation" = ANY (ARRAY['EN'::"text", 'NI'::"text", 'SC'::"text", 'WS'::"text"]))),
    CONSTRAINT "epr_submission_lines_rpd_material_weight_kg_check" CHECK (("rpd_material_weight_kg" > (0)::numeric)),
    CONSTRAINT "epr_submission_lines_rpd_organisation_size_check" CHECK (("rpd_organisation_size" = ANY (ARRAY['L'::"text", 'S'::"text"]))),
    CONSTRAINT "epr_submission_lines_rpd_packaging_activity_check" CHECK (("rpd_packaging_activity" = ANY (ARRAY['SO'::"text", 'PF'::"text", 'IM'::"text", 'SE'::"text", 'HL'::"text", 'OM'::"text"]))),
    CONSTRAINT "epr_submission_lines_rpd_packaging_material_check" CHECK (("rpd_packaging_material" = ANY (ARRAY['AL'::"text", 'FC'::"text", 'GL'::"text", 'PC'::"text", 'PL'::"text", 'ST'::"text", 'WD'::"text", 'OT'::"text"]))),
    CONSTRAINT "epr_submission_lines_rpd_packaging_type_check" CHECK (("rpd_packaging_type" = ANY (ARRAY['HH'::"text", 'NH'::"text", 'CW'::"text", 'OW'::"text", 'PB'::"text", 'RU'::"text", 'HDC'::"text", 'NDC'::"text", 'SP'::"text"]))),
    CONSTRAINT "epr_submission_lines_rpd_recyclability_rating_check" CHECK ((("rpd_recyclability_rating" IS NULL) OR ("rpd_recyclability_rating" = ANY (ARRAY['R'::"text", 'A'::"text", 'G'::"text", 'R-M'::"text", 'A-M'::"text", 'G-M'::"text"])))),
    CONSTRAINT "epr_submission_lines_rpd_to_nation_check" CHECK ((("rpd_to_nation" IS NULL) OR ("rpd_to_nation" = ANY (ARRAY['EN'::"text", 'NI'::"text", 'SC'::"text", 'WS'::"text"]))))
);


ALTER TABLE "public"."epr_submission_lines" OWNER TO "postgres";


COMMENT ON TABLE "public"."epr_submission_lines" IS 'Individual RPD line items, mapping 1:1 to rows in the CSV export. Each line traces back to a specific product and packaging material.';



COMMENT ON COLUMN "public"."epr_submission_lines"."rpd_packaging_activity" IS 'SO=Sold (Brand Owner), PF=Packed/Filled, IM=Imported, SE=Sold via online marketplace, HL=Hired/Loaned, OM=Online marketplace operator.';



COMMENT ON COLUMN "public"."epr_submission_lines"."rpd_packaging_type" IS 'HH=Household, NH=Non-household, CW=Consumer waste (self-managed), OW=Organisation waste, PB=Public bin, RU=Reusable, HDC=Household drinks container, NDC=Non-household drinks container, SP=Street/public.';



COMMENT ON COLUMN "public"."epr_submission_lines"."rpd_packaging_class" IS 'P1-P6=Primary, O1=Secondary, O2=Shipment, B1=Tertiary. Number suffix follows Defra packaging class codes.';



COMMENT ON COLUMN "public"."epr_submission_lines"."is_drs_excluded" IS 'True if this is an aluminium/PET/steel drinks container 150ml-3L — excluded from EPR waste management fees as it will enter DRS.';



CREATE TABLE IF NOT EXISTS "public"."epr_submissions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "organization_id" "uuid" NOT NULL,
    "submission_period" "text" NOT NULL,
    "fee_year" "text" NOT NULL,
    "organization_size" "text" NOT NULL,
    "status" "text" DEFAULT 'draft'::"text" NOT NULL,
    "total_packaging_weight_kg" numeric DEFAULT 0 NOT NULL,
    "total_estimated_fee_gbp" numeric DEFAULT 0 NOT NULL,
    "total_line_items" integer DEFAULT 0 NOT NULL,
    "material_summary" "jsonb" DEFAULT '{}'::"jsonb",
    "csv_generated_at" timestamp with time zone,
    "csv_storage_path" "text",
    "csv_checksum" "text",
    "submitted_to_rpd_at" timestamp with time zone,
    "submitted_by" "uuid",
