);


ALTER TABLE "public"."epr_submissions" OWNER TO "postgres";


COMMENT ON TABLE "public"."epr_submissions" IS 'RPD submission batches. Each covers a reporting period (H1 Jan-Jun, H2 Jul-Dec for Large; P0 full year for Small).';



COMMENT ON COLUMN "public"."epr_submissions"."material_summary" IS 'Denormalized JSONB: { "GL": { weight_kg: 1500, fee_gbp: 288, count: 5 }, ... } for dashboard charts.';



COMMENT ON COLUMN "public"."epr_submissions"."csv_checksum" IS 'SHA-256 hash of the generated CSV file for integrity verification during audit.';



