    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "flag_targets_base_year_check" CHECK ((("base_year" >= 2015) AND ("base_year" <= 2030))),
    CONSTRAINT "flag_targets_reduction_percentage_check" CHECK ((("reduction_percentage" > (0)::numeric) AND ("reduction_percentage" <= (100)::numeric))),
    CONSTRAINT "flag_targets_sbti_pathway_check" CHECK (("sbti_pathway" = ANY (ARRAY['flag_1_5c'::"text", 'flag_well_below_2c'::"text"]))),
    CONSTRAINT "flag_targets_scope_check" CHECK (("scope" = ANY (ARRAY['flag'::"text", 'non_flag'::"text", 'combined'::"text"]))),
    CONSTRAINT "flag_targets_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'submitted'::"text", 'validated'::"text", 'expired'::"text"]))),
    CONSTRAINT "flag_targets_target_type_check" CHECK (("target_type" = ANY (ARRAY['absolute'::"text", 'intensity'::"text"]))),
    CONSTRAINT "flag_targets_target_year_check" CHECK ((("target_year" >= 2025) AND ("target_year" <= 2050)))
);


ALTER TABLE "public"."flag_targets" OWNER TO "postgres";


