    "sensitivity_results" "jsonb" DEFAULT '[]'::"jsonb",
    "highly_sensitive_parameters" "text"[] DEFAULT '{}'::"text"[],
    "consistency_issues" "text"[] DEFAULT '{}'::"text"[],
    "methodology_consistent" boolean DEFAULT true,
    "temporal_consistency" "jsonb" DEFAULT '{}'::"jsonb",
    "geographic_consistency" "jsonb" DEFAULT '{}'::"jsonb",
    "key_findings" "text"[] DEFAULT '{}'::"text"[],
    "limitations" "text"[] DEFAULT '{}'::"text"[],
    "recommendations" "text"[] DEFAULT '{}'::"text"[],
    "uncertainty_statement" "text",
