    "organization_id" "uuid" NOT NULL,
    "barrel_type" "text" DEFAULT 'american_oak_200'::"text" NOT NULL,
    "barrel_volume_litres" numeric(8,2) DEFAULT 200 NOT NULL,
    "barrel_use_number" integer DEFAULT 1 NOT NULL,
    "barrel_co2e_new" numeric(8,4),
    "aging_duration_months" integer DEFAULT 12 NOT NULL,
    "angel_share_percent_per_year" numeric(5,2) DEFAULT 2.0 NOT NULL,
    "climate_zone" "text" DEFAULT 'temperate'::"text" NOT NULL,
    "fill_volume_litres" numeric(8,2) NOT NULL,
    "number_of_barrels" integer DEFAULT 1 NOT NULL,
    "warehouse_energy_kwh_per_barrel_year" numeric(8,4) DEFAULT 15.0,
    "warehouse_energy_source" "text" DEFAULT 'grid_electricity'::"text",
    "allocation_method" "text" DEFAULT 'cut_off'::"text" NOT NULL,
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    "bottles_produced" integer,
    "cask_fill_abv_percent" numeric(5,2),
    "warehouse_country_code" "text",
    CONSTRAINT "mp_aging_duration_positive" CHECK (("aging_duration_months" > 0)),
    CONSTRAINT "mp_allocation_method_check" CHECK (("allocation_method" = ANY (ARRAY['cut_off'::"text", 'avoided_burden'::"text"]))),
    CONSTRAINT "mp_angel_share_range" CHECK ((("angel_share_percent_per_year" >= (0)::numeric) AND ("angel_share_percent_per_year" <= (25)::numeric))),
    CONSTRAINT "mp_barrel_type_check" CHECK (("barrel_type" = ANY (ARRAY['american_oak_200'::"text", 'french_oak_225'::"text", 'american_oak_500'::"text", 'custom'::"text"]))),
    CONSTRAINT "mp_barrel_use_positive" CHECK (("barrel_use_number" > 0)),
    CONSTRAINT "mp_cask_fill_abv_range" CHECK ((("cask_fill_abv_percent" IS NULL) OR (("cask_fill_abv_percent" >= (0)::numeric) AND ("cask_fill_abv_percent" <= (100)::numeric)))),
    CONSTRAINT "mp_climate_zone_check" CHECK (("climate_zone" = ANY (ARRAY['temperate'::"text", 'continental'::"text", 'tropical'::"text"]))),
    CONSTRAINT "mp_fill_volume_positive" CHECK (("fill_volume_litres" > (0)::numeric)),
    CONSTRAINT "mp_number_of_barrels_positive" CHECK (("number_of_barrels" > 0)),
    CONSTRAINT "mp_warehouse_country_iso2" CHECK ((("warehouse_country_code" IS NULL) OR ("char_length"("warehouse_country_code") = 2))),
    CONSTRAINT "mp_warehouse_energy_source_check" CHECK (("warehouse_energy_source" = ANY (ARRAY['grid_electricity'::"text", 'natural_gas'::"text", 'renewable'::"text", 'mixed'::"text"])))
);


