COMMENT ON COLUMN "public"."maturation_profiles"."bottles_produced" IS 'Optional override: exact number of bottles produced from this maturation batch. When NULL, per-bottle allocation is derived from output_volume / product bottle size. Use for single-cask bottlings where exact yield is known.';



COMMENT ON COLUMN "public"."maturation_profiles"."cask_fill_abv_percent" IS 'Alcohol strength at cask fill, before dilution at bottling. Typical values: Scotch 63.5, bourbon 62.5, cognac 70, rum 65. NULL falls back to product-category default then 63%.';



COMMENT ON COLUMN "public"."maturation_profiles"."warehouse_country_code" IS 'ISO 3166-1 alpha-2 country code for the maturation warehouse. Drives the electricity grid emission factor for warehouse_energy. NULL falls back to primary facility country then global average.';



CREATE OR REPLACE VIEW "public"."member_profiles" WITH ("security_invoker"='true') AS
 SELECT "om"."id" AS "membership_id",
    "om"."organization_id",
    "om"."user_id",
    "om"."role_id",
    "r"."name" AS "role",
    "p"."email",
    "p"."full_name",
    "p"."avatar_url",
    "p"."phone",
    "p"."created_at" AS "profile_created_at",
    "p"."updated_at" AS "profile_updated_at",
    "om"."joined_at",
    "om"."invited_by"
   FROM (("public"."organization_members" "om"
     JOIN "public"."profiles" "p" ON (("om"."user_id" = "p"."id")))
     LEFT JOIN "public"."roles" "r" ON (("om"."role_id" = "r"."id")));


ALTER VIEW "public"."member_profiles" OWNER TO "postgres";


COMMENT ON VIEW "public"."member_profiles" IS 'Secure view combining organization_members with profiles. Uses security_invoker=true to inherit RLS from base tables. Users automatically see only members from their organization via get_current_organization_id() check on organization_members table.';



