    CONSTRAINT "orchard_growing_profiles_ecosystem_type_check" CHECK (("ecosystem_type" = ANY (ARRAY['temperate_forest'::"text", 'mediterranean'::"text", 'grassland'::"text", 'wetland'::"text", 'shrubland'::"text", 'tropical_forest'::"text", 'boreal_forest'::"text", 'semi_arid'::"text", 'other'::"text"]))),
    CONSTRAINT "orchard_growing_profiles_fertiliser_type_check" CHECK (("fertiliser_type" = ANY (ARRAY['none'::"text", 'synthetic_n'::"text", 'organic_manure'::"text", 'organic_compost'::"text", 'mixed'::"text"]))),
    CONSTRAINT "orchard_growing_profiles_fruit_yield_tonnes_check" CHECK (("fruit_yield_tonnes" >= (0)::numeric)),
    CONSTRAINT "orchard_growing_profiles_herbicide_type_check" CHECK ((("herbicide_type" IS NULL) OR ("herbicide_type" = ANY (ARRAY['generic'::"text", 'sulfur'::"text", 'mancozeb'::"text", 'synthetic_fungicide'::"text", 'insecticide_codling_moth'::"text", 'insecticide_aphid'::"text", 'herbicide_glyphosate'::"text"])))),
    CONSTRAINT "orchard_growing_profiles_irrigation_energy_source_check" CHECK (("irrigation_energy_source" = ANY (ARRAY['grid_electricity'::"text", 'diesel_pump'::"text", 'solar_pump'::"text", 'gravity_fed'::"text", 'none'::"text"]))),
    CONSTRAINT "orchard_growing_profiles_land_ownership_type_check" CHECK (("land_ownership_type" = ANY (ARRAY['owned'::"text", 'leased'::"text", 'rental'::"text", 'contract_growing'::"text"]))),
    CONSTRAINT "orchard_growing_profiles_pesticide_type_check" CHECK ((("pesticide_type" IS NULL) OR ("pesticide_type" = ANY (ARRAY['generic'::"text", 'sulfur'::"text", 'mancozeb'::"text", 'synthetic_fungicide'::"text", 'insecticide_codling_moth'::"text", 'insecticide_aphid'::"text", 'herbicide_glyphosate'::"text"])))),
    CONSTRAINT "orchard_growing_profiles_pruning_residue_burned_kg_per_ha_check" CHECK (("pruning_residue_burned_kg_per_ha" > (0)::numeric)),
    CONSTRAINT "orchard_growing_profiles_pruning_residue_management_type_check" CHECK (("pruning_residue_management_type" = ANY (ARRAY['in_field'::"text", 'removed_for_biomass'::"text", 'chipped_and_spread'::"text", 'burned'::"text"]))),
    CONSTRAINT "orchard_growing_profiles_pruning_residue_measured_kg_per__check" CHECK (("pruning_residue_measured_kg_per_ha" > (0)::numeric)),
    CONSTRAINT "orchard_growing_profiles_red_diesel_litres_per_year_check" CHECK ((("red_diesel_litres_per_year" IS NULL) OR ("red_diesel_litres_per_year" >= (0)::numeric))),
    CONSTRAINT "orchard_growing_profiles_removal_verification_status_check" CHECK (("removal_verification_status" = ANY (ARRAY['unverified'::"text", 'pending'::"text", 'verified'::"text", 'rejected'::"text", 'expired'::"text"]))),
    CONSTRAINT "orchard_growing_profiles_soil_management_check" CHECK (("soil_management" = ANY (ARRAY['conventional_tillage'::"text", 'minimum_tillage'::"text", 'no_till'::"text", 'cover_cropping'::"text", 'composting'::"text", 'biochar_compost'::"text", 'regenerative_integrated'::"text"]))),
    CONSTRAINT "orchard_growing_profiles_transport_mode_check" CHECK ((("transport_mode" IS NULL) OR ("transport_mode" = ANY (ARRAY['road'::"text", 'rail'::"text"])))),
    CONSTRAINT "orchard_growing_profiles_water_stress_index_check" CHECK (("water_stress_index" = ANY (ARRAY['low'::"text", 'medium'::"text", 'high'::"text", 'very_high'::"text"])))
);


ALTER TABLE "public"."orchard_growing_profiles" OWNER TO "postgres";


COMMENT ON COLUMN "public"."orchard_growing_profiles"."land_ownership_type" IS 'GHG Protocol LSR v1.0 operational boundary definition';



COMMENT ON COLUMN "public"."orchard_growing_profiles"."lease_expiry_date" IS 'Required if land_ownership_type is leased or rental';



COMMENT ON COLUMN "public"."orchard_growing_profiles"."is_boundary_controlled" IS 'Whether the organisation controls land management decisions on this land';



COMMENT ON COLUMN "public"."orchard_growing_profiles"."pruning_residue_management_type" IS 'How tree prunings are managed. in_field = left to decompose (default IPCC N2O applies). removed_for_biomass = N leaves system, zero N2O. chipped_and_spread = adjusted decomposition factor.';



COMMENT ON COLUMN "public"."orchard_growing_profiles"."pruning_residue_measured_kg_per_ha" IS 'Measured dry matter from prunings in kg/ha/yr. If provided, overrides the per-crop-type pruning_dm_per_ha default constant. Raises data quality to primary.';



COMMENT ON COLUMN "public"."orchard_growing_profiles"."removal_verification_status" IS 'Third-party verification status for soil carbon removal claims';



COMMENT ON COLUMN "public"."orchard_growing_profiles"."removal_verifier_body" IS 'Name of the third-party verification body (e.g. SCS Global Services, Verra)';



COMMENT ON COLUMN "public"."orchard_growing_profiles"."removal_verifier_standard" IS 'Verification standard used (e.g. ISO 14064-3, Verra VCS, Gold Standard)';



COMMENT ON COLUMN "public"."orchard_growing_profiles"."removal_verification_date" IS 'Date verification was completed';



COMMENT ON COLUMN "public"."orchard_growing_profiles"."removal_verification_expiry" IS 'Date verification expires and re-verification is required';



COMMENT ON COLUMN "public"."orchard_growing_profiles"."ecosystem_type" IS 'TNFD LEAP Locate phase: ecosystem type at the production location per IPBES categories.';



COMMENT ON COLUMN "public"."orchard_growing_profiles"."in_biodiversity_sensitive_area" IS 'Whether the site is within or adjacent to a Key Biodiversity Area, UNESCO World Heritage Site, Ramsar wetland, or protected area.';



COMMENT ON COLUMN "public"."orchard_growing_profiles"."sensitive_area_details" IS 'Name and designation of the biodiversity-sensitive area (if applicable).';



COMMENT ON COLUMN "public"."orchard_growing_profiles"."water_stress_index" IS 'WRI Aqueduct or equivalent water stress classification for the location.';



COMMENT ON COLUMN "public"."orchard_growing_profiles"."pruning_residue_burned_kg_per_ha" IS 'Dry matter of prunings burned in-field (kg/ha/yr). If NULL when management type = burned, the per-crop-type pruning DM default is used. Drives IPCC 2006 Vol 4 Ch 2.4 field-burning CH4/N2O (biogenic CO2 excluded).';



COMMENT ON COLUMN "public"."orchard_growing_profiles"."red_diesel_litres_per_year" IS 'Red / agricultural (gas oil) diesel for off-road orchard machinery, litres/yr. Priced with DEFRA red-diesel factor (distinct from road diesel). NULL = none.';



