    CONSTRAINT "orchards_climate_zone_check" CHECK (("climate_zone" = ANY (ARRAY['wet'::"text", 'dry'::"text", 'temperate'::"text"]))),
    CONSTRAINT "orchards_hectares_check" CHECK (("hectares" > (0)::numeric)),
    CONSTRAINT "orchards_land_conversion_year_check" CHECK ((("land_conversion_year" IS NULL) OR (("land_conversion_year" >= 1900) AND ("land_conversion_year" <= 2100)))),
    CONSTRAINT "orchards_orchard_type_check" CHECK (("orchard_type" = ANY (ARRAY['apple'::"text", 'pear'::"text", 'cherry'::"text", 'plum'::"text", 'citrus'::"text", 'stone_fruit'::"text", 'mixed'::"text", 'other'::"text"]))),
