    CONSTRAINT "orchards_training_system_check" CHECK ((("training_system" IS NULL) OR ("training_system" = ANY (ARRAY['bush'::"text", 'spindle'::"text", 'espalier'::"text", 'trellis'::"text", 'central_leader'::"text", 'open_vase'::"text", 'other'::"text"])))),
    CONSTRAINT "orchards_tree_density_per_ha_check" CHECK ((("tree_density_per_ha" IS NULL) OR ("tree_density_per_ha" > 0)))
);


