CREATE OR REPLACE VIEW "public"."peer_benchmark_view" AS
 WITH "latest_per_org" AS (
         SELECT DISTINCT ON ("metric_snapshots"."organization_id", "metric_snapshots"."metric_key") "metric_snapshots"."organization_id",
            "metric_snapshots"."metric_key",
            "metric_snapshots"."value",
            "metric_snapshots"."snapshot_date"
           FROM "public"."metric_snapshots"
          WHERE ("metric_snapshots"."snapshot_date" >= (CURRENT_DATE - '90 days'::interval))
          ORDER BY "metric_snapshots"."organization_id", "metric_snapshots"."metric_key", "metric_snapshots"."snapshot_date" DESC
        )
 SELECT "metric_key",
    "count"(*) AS "sample_size",
    "percentile_cont"((0.25)::double precision) WITHIN GROUP (ORDER BY (("value")::double precision)) AS "p25",
    "percentile_cont"((0.5)::double precision) WITHIN GROUP (ORDER BY (("value")::double precision)) AS "p50",
    "percentile_cont"((0.75)::double precision) WITHIN GROUP (ORDER BY (("value")::double precision)) AS "p75",
    "min"("value") AS "min_value",
    "max"("value") AS "max_value",
    "avg"("value") AS "mean_value"
   FROM "latest_per_org"
  GROUP BY "metric_key"
 HAVING ("count"(*) >= 5);


ALTER VIEW "public"."peer_benchmark_view" OWNER TO "postgres";


COMMENT ON VIEW "public"."peer_benchmark_view" IS 'Pulse: anonymised cross-org metric percentiles (k-anonymity ≥ 5). Read by /api/pulse/peer-benchmark.';



