CREATE TABLE IF NOT EXISTS "public"."product_materials" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "product_id" bigint NOT NULL,
    "material_name" "text" NOT NULL,
    "material_id" "uuid",
    "material_type" "text",
    "quantity" numeric(12,6) NOT NULL,
    "unit" "text",
    "lca_stage_id" bigint,
    "lca_sub_stage_id" bigint,
    "data_source" "text",
    "data_source_id" "text",
    "supplier_product_id" "uuid",
    "origin_country" "text",
    "is_organic_certified" boolean DEFAULT false,
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    "packaging_category" "text",
    "transport_mode" "text",
    "distance_km" numeric,
    "transport_emissions" numeric,
    "origin_lat" numeric,
    "origin_lng" numeric,
    "origin_address" "text",
    "origin_country_code" "text",
    "category_type" "public"."material_category_type",
    "epr_is_drinks_container" boolean DEFAULT false,
    "epr_is_household" boolean DEFAULT false,
    "has_component_breakdown" boolean DEFAULT false,
    "component_glass_weight" numeric DEFAULT 0,
    "component_aluminium_weight" numeric DEFAULT 0,
    "component_steel_weight" numeric DEFAULT 0,
    "component_paper_weight" numeric DEFAULT 0,
    "component_wood_weight" numeric DEFAULT 0,
    "component_other_weight" numeric DEFAULT 0,
    "epr_class" "text",
    "epr_subclass" "text",
    "epr_material_type" "text",
    "epr_recyclability" "text",
    "epr_producer_id" "text",
    "total_weight_kg" numeric,
    "net_weight_g" numeric,
    "printing_process" "text",
    "recycled_content_percentage" numeric,
    "epr_packaging_activity" "text",
    "epr_packaging_level" "text",
    "epr_ram_rating" "text",
    "epr_uk_nation" "text",
    "units_per_group" integer DEFAULT 1,
    "matched_source_name" "text",
    "inbound_container_type" "text",
    "inbound_container_volume_l" numeric,
    "inbound_container_tare_kg" numeric,
    "inbound_container_reuse_cycles" integer DEFAULT 1,
    "inbound_container_ef" numeric,
    "transport_legs" "jsonb",
    "vineyard_id" "uuid",
    "is_self_grown" boolean DEFAULT false NOT NULL,
    "cached_co2_factor" numeric,
    "openlca_database" "text" DEFAULT 'ecoinvent'::"text",
    "ef_source_type" "text",
    "orchard_id" "uuid",
    "is_biogenic_carbon" boolean DEFAULT false NOT NULL,
    "arable_field_id" "uuid",
    "inbound_container_material" "text",
    "reuse_trips" integer,
    "end_of_life_pathway" "text",
    "recyclability_percent" numeric(5,2),
    "biobased_content_percentage" numeric(5,2),
    "stage_id" "uuid",
    "container_format" "text",
    "container_material" "text",
    "container_size_ml" numeric,
    "weight_source" "text",
    "match_status" "text",
    "openlca_no_match_at" timestamp with time zone,
    CONSTRAINT "check_epr_packaging_activity" CHECK ((("epr_packaging_activity" IS NULL) OR ("epr_packaging_activity" = ANY (ARRAY['brand'::"text", 'packed_filled'::"text", 'imported'::"text", 'empty'::"text", 'hired'::"text", 'marketplace'::"text"])))),
    CONSTRAINT "check_epr_packaging_level" CHECK ((("epr_packaging_level" IS NULL) OR ("epr_packaging_level" = ANY (ARRAY['primary'::"text", 'secondary'::"text", 'tertiary'::"text", 'shipment'::"text"])))),
    CONSTRAINT "check_epr_ram_rating" CHECK ((("epr_ram_rating" IS NULL) OR ("epr_ram_rating" = ANY (ARRAY['red'::"text", 'amber'::"text", 'green'::"text"])))),
    CONSTRAINT "check_epr_uk_nation" CHECK ((("epr_uk_nation" IS NULL) OR ("epr_uk_nation" = ANY (ARRAY['england'::"text", 'scotland'::"text", 'wales'::"text", 'northern_ireland'::"text"])))),
    CONSTRAINT "check_packaging_category" CHECK ((("packaging_category" IS NULL) OR ("packaging_category" = ANY (ARRAY['container'::"text", 'label'::"text", 'closure'::"text", 'secondary'::"text", 'shipment'::"text", 'tertiary'::"text"])))),
    CONSTRAINT "check_pm_openlca_database" CHECK (("openlca_database" = ANY (ARRAY['ecoinvent'::"text", 'agribalyse'::"text"]))),
    CONSTRAINT "data_source_integrity" CHECK (((("data_source" = 'openlca'::"text") AND ("data_source_id" IS NOT NULL)) OR (("data_source" = 'supplier'::"text") AND ("supplier_product_id" IS NOT NULL)) OR (("data_source" = 'breww_recipe_avg'::"text") AND ("data_source_id" IS NOT NULL)) OR ("data_source" = 'breww_sku_container'::"text") OR (("data_source" = 'unleashed_bom'::"text") AND ("data_source_id" IS NOT NULL)) OR ("data_source" IS NULL))),
    CONSTRAINT "inbound_container_ingredient_only" CHECK ((("inbound_container_type" IS NULL) OR ("material_type" = 'ingredient'::"text"))),
    CONSTRAINT "inbound_container_reuse_cycles_min" CHECK ((("inbound_container_reuse_cycles" IS NULL) OR ("inbound_container_reuse_cycles" >= 1))),
    CONSTRAINT "origin_coordinates_completeness" CHECK (((("origin_lat" IS NULL) AND ("origin_lng" IS NULL)) OR (("origin_lat" IS NOT NULL) AND ("origin_lng" IS NOT NULL)))),
    CONSTRAINT "positive_quantity" CHECK (("quantity" > (0)::numeric)),
    CONSTRAINT "product_materials_biobased_content_percentage_check" CHECK ((("biobased_content_percentage" IS NULL) OR (("biobased_content_percentage" >= (0)::numeric) AND ("biobased_content_percentage" <= (100)::numeric)))),
    CONSTRAINT "product_materials_distance_km_check" CHECK ((("distance_km" IS NULL) OR ("distance_km" >= (0)::numeric))),
    CONSTRAINT "product_materials_end_of_life_pathway_check" CHECK ((("end_of_life_pathway" IS NULL) OR ("end_of_life_pathway" = ANY (ARRAY['landfill'::"text", 'incineration'::"text", 'recycling'::"text", 'composting'::"text", 'reuse'::"text", 'unknown'::"text"])))),
    CONSTRAINT "product_materials_match_status_check" CHECK ((("match_status" IS NULL) OR ("match_status" = ANY (ARRAY['verified'::"text", 'auto_matched'::"text", 'needs_review'::"text"])))),
    CONSTRAINT "product_materials_origin_country_code_check" CHECK ((("origin_country_code" IS NULL) OR ("length"("origin_country_code") = 2))),
    CONSTRAINT "product_materials_origin_lat_check" CHECK ((("origin_lat" IS NULL) OR (("origin_lat" >= ('-90'::integer)::numeric) AND ("origin_lat" <= (90)::numeric)))),
    CONSTRAINT "product_materials_origin_lng_check" CHECK ((("origin_lng" IS NULL) OR (("origin_lng" >= ('-180'::integer)::numeric) AND ("origin_lng" <= (180)::numeric)))),
    CONSTRAINT "product_materials_recyclability_percent_check" CHECK ((("recyclability_percent" IS NULL) OR (("recyclability_percent" >= (0)::numeric) AND ("recyclability_percent" <= (100)::numeric)))),
    CONSTRAINT "product_materials_reuse_trips_check" CHECK ((("reuse_trips" IS NULL) OR ("reuse_trips" >= 1))),
    CONSTRAINT "product_materials_transport_mode_check" CHECK (("transport_mode" = ANY (ARRAY['truck'::"text", 'train'::"text", 'ship'::"text", 'air'::"text"]))),
    CONSTRAINT "product_materials_unit_check" CHECK (("lower"(TRIM(BOTH FROM COALESCE("unit", ''::"text"))) = ANY (ARRAY['kg'::"text", 'g'::"text", 'mg'::"text", 't'::"text", 'lb'::"text", 'oz'::"text", 'l'::"text", 'ml'::"text", 'unit'::"text", 'kilogram'::"text", 'kilograms'::"text", 'kgs'::"text", 'gram'::"text", 'grams'::"text", 'milligram'::"text", 'milligrams'::"text", 'tonne'::"text", 'tonnes'::"text", 'metric_ton'::"text", 'metric_tons'::"text", 'metric ton'::"text", 'metric tons'::"text", 'lbs'::"text", 'pound'::"text", 'pounds'::"text", 'ounce'::"text", 'ounces'::"text", 'litre'::"text", 'litres'::"text", 'liter'::"text", 'liters'::"text", 'millilitre'::"text", 'millilitres'::"text", 'milliliter'::"text", 'milliliters'::"text", 'units'::"text", 'item'::"text", 'items'::"text", 'piece'::"text", 'pieces'::"text", 'each'::"text", 'ea'::"text", 'pcs'::"text"]))),
    CONSTRAINT "product_materials_unit_vocabulary" CHECK ((("unit" IS NULL) OR ("unit" = ANY (ARRAY['kg'::"text", 'g'::"text", 'mg'::"text", 't'::"text", 'lb'::"text", 'oz'::"text", 'l'::"text", 'ml'::"text", 'unit'::"text"])))),
    CONSTRAINT "product_materials_units_per_group_check" CHECK (("units_per_group" >= 1)),
    CONSTRAINT "product_materials_weight_source_check" CHECK ((("weight_source" IS NULL) OR ("weight_source" = ANY (ARRAY['measured'::"text", 'typical'::"text", 'estimated'::"text"])))),
    CONSTRAINT "transport_data_completeness" CHECK (((("transport_mode" IS NULL) AND ("distance_km" IS NULL)) OR (("transport_mode" IS NOT NULL) AND ("distance_km" IS NOT NULL)))),
    CONSTRAINT "valid_data_source" CHECK ((("data_source" IS NULL) OR ("data_source" = ANY (ARRAY['openlca'::"text", 'supplier'::"text", 'breww_recipe_avg'::"text", 'breww_sku_container'::"text", 'unleashed_bom'::"text"])))),
    CONSTRAINT "valid_material_type" CHECK ((("material_type" IS NULL) OR ("material_type" = ANY (ARRAY['ingredient'::"text", 'packaging'::"text"]))))
);


ALTER TABLE "public"."product_materials" OWNER TO "postgres";


COMMENT ON TABLE "public"."product_materials" IS 'Master bill of materials template for products. Materials are copied from here to product_lca_materials when creating new LCA calculations.';



COMMENT ON COLUMN "public"."product_materials"."product_id" IS 'Foreign key linking to the parent product.';



COMMENT ON COLUMN "public"."product_materials"."material_name" IS 'Display name for the material (e.g., "Organic Wheat Flour", "Glass Bottle").';



COMMENT ON COLUMN "public"."product_materials"."material_id" IS 'UUID referencing either ingredients or packaging_types table (determined by material_type).';



COMMENT ON COLUMN "public"."product_materials"."material_type" IS 'Discriminator field: "ingredient" or "packaging" indicating which table material_id references.';



COMMENT ON COLUMN "public"."product_materials"."quantity" IS 'Default amount of material used in the product. Units specified in unit column.';



COMMENT ON COLUMN "public"."product_materials"."unit" IS 'Unit of measurement for quantity (kg, L, units, etc).';



COMMENT ON COLUMN "public"."product_materials"."lca_stage_id" IS 'Which LCA lifecycle stage this material belongs to (A1-A3, B1-B7, C1-C4, D).';



COMMENT ON COLUMN "public"."product_materials"."lca_sub_stage_id" IS 'Specific sub-stage within the LCA stage.';



COMMENT ON COLUMN "public"."product_materials"."data_source" IS 'Data provenance: "openlca" for OpenLCA database, "supplier" for internal supplier network.';



COMMENT ON COLUMN "public"."product_materials"."data_source_id" IS 'External system identifier - stores OpenLCA process UUID when data_source is "openlca".';



COMMENT ON COLUMN "public"."product_materials"."supplier_product_id" IS 'Foreign key to supplier_products table when data_source is "supplier".';



COMMENT ON COLUMN "public"."product_materials"."origin_country" IS 'Country or region of origin for the material.';



COMMENT ON COLUMN "public"."product_materials"."is_organic_certified" IS 'Indicates whether the material has organic certification.';



COMMENT ON COLUMN "public"."product_materials"."notes" IS 'User-entered notes about this material for documentation purposes.';



COMMENT ON COLUMN "public"."product_materials"."transport_mode" IS 'Mode of transport from origin to facility. Must match DEFRA freight categories: truck, train, ship, or air.';



COMMENT ON COLUMN "public"."product_materials"."distance_km" IS 'Distance in kilometres from material origin to production facility. Used to calculate transport emissions.';



COMMENT ON COLUMN "public"."product_materials"."transport_emissions" IS 'Calculated transport emissions in kg CO2e. Computed using: (weight_kg / 1000) × distance_km × emission_factor';



COMMENT ON COLUMN "public"."product_materials"."origin_lat" IS 'Latitude coordinate of material origin. Must be between -90 and 90 degrees.';



COMMENT ON COLUMN "public"."product_materials"."origin_lng" IS 'Longitude coordinate of material origin. Must be between -180 and 180 degrees.';



COMMENT ON COLUMN "public"."product_materials"."origin_address" IS 'Full address of material origin location for supply chain mapping.';



COMMENT ON COLUMN "public"."product_materials"."origin_country_code" IS 'ISO 3166-1 alpha-2 country code (2 letters) for material origin country.';



COMMENT ON COLUMN "public"."product_materials"."category_type" IS 'Auto-detected category based on material name and usage';



COMMENT ON COLUMN "public"."product_materials"."epr_packaging_activity" IS 'EPR packaging activity: how the packaging was supplied to the UK market (brand/packed_filled/imported/empty/hired/marketplace)';



COMMENT ON COLUMN "public"."product_materials"."epr_packaging_level" IS 'EPR packaging level: primary/secondary/tertiary/shipment';



COMMENT ON COLUMN "public"."product_materials"."epr_ram_rating" IS 'Recyclability Assessment Methodology (RAM) rating: red/amber/green — determines fee modulation from Year 2';



COMMENT ON COLUMN "public"."product_materials"."epr_uk_nation" IS 'UK nation where packaging is supplied/discarded: england/scotland/wales/northern_ireland';



COMMENT ON COLUMN "public"."product_materials"."units_per_group" IS 'Number of product units served by this packaging item. 1 for primary packaging (container/label/closure). >1 for secondary/shipment/tertiary. Used for ISO 14044 physical allocation.';



COMMENT ON COLUMN "public"."product_materials"."matched_source_name" IS 'The database emission factor name when a proxy was used. NULL means material_name is the exact match.';



COMMENT ON COLUMN "public"."product_materials"."inbound_container_type" IS 'Preset container type key or ''custom''. NULL = no container recorded. Bulk: ibc_1000l, ibc_500l, drum_200l, flexitank_24000l, bulk_tanker_25000l. Bottles: bottle_700ml_glass, bottle_750ml_glass, bottle_1l_glass. Or: custom.';



COMMENT ON COLUMN "public"."product_materials"."inbound_container_volume_l" IS 'Nominal container volume in litres. Pre-populated from preset; editable for ''custom''.';



COMMENT ON COLUMN "public"."product_materials"."inbound_container_tare_kg" IS 'Empty container weight in kg. Pre-populated from preset; editable for ''custom''.';



COMMENT ON COLUMN "public"."product_materials"."inbound_container_reuse_cycles" IS 'Number of times this container is reused (including this trip). 1 = one-way; >1 = reusable (carbon amortised across cycles).';



COMMENT ON COLUMN "public"."product_materials"."inbound_container_ef" IS 'Override emission factor in kg CO₂e/kg container material. NULL = auto-lookup from staging_emission_factors by container type. Only used for ''custom'' container entries.';



COMMENT ON COLUMN "public"."product_materials"."transport_legs" IS 'Multi-modal inbound transport legs (DistributionLeg[]). When present, overrides the single transport_mode + distance_km fields. Each leg: { id, label, transportMode, distanceKm }. transportMode ∈ {truck, train, ship, air}.';



COMMENT ON COLUMN "public"."product_materials"."cached_co2_factor" IS 'kg CO2e per reference unit, cached at assignment time as a resolver fallback';



COMMENT ON COLUMN "public"."product_materials"."openlca_database" IS 'Which OpenLCA database the linked process UUID belongs to (ecoinvent or agribalyse)';



COMMENT ON COLUMN "public"."product_materials"."orchard_id" IS 'Links a self-grown ingredient to the orchard it was harvested from. Used by the LCA calculator to pull field-level emissions from orchard_growing_profiles.';



COMMENT ON COLUMN "public"."product_materials"."is_biogenic_carbon" IS 'User-declared: carbon from this material is biogenic (fermentation, plant growth)';



COMMENT ON COLUMN "public"."product_materials"."arable_field_id" IS 'Links a self-grown ingredient to the arable field it was harvested from. Used by the LCA calculator to pull field-level emissions from arable_growing_profiles.';



COMMENT ON COLUMN "public"."product_materials"."inbound_container_material" IS 'Material of the inbound delivery container (e.g. HDPE, LDPE, steel, glass, aluminium). Used to look up the manufacturing emission factor when container type is ''custom'' and no manual EF override is provided.';



COMMENT ON COLUMN "public"."product_materials"."container_format" IS 'Structured packaging format from the guided wizard (bottle, can, keg, carton, pouch, bag_in_box). Null for manually-entered rows.';



COMMENT ON COLUMN "public"."product_materials"."container_material" IS 'Structured material identity from the guided wizard (glass, aluminium, pet, hdpe, steel, paperboard, cork, plastic_laminate, bib_composite, paper). End-of-life factor resolution prefers this over name inference.';



COMMENT ON COLUMN "public"."product_materials"."container_size_ml" IS 'Container capacity in millilitres, when chosen in the guided wizard.';



COMMENT ON COLUMN "public"."product_materials"."weight_source" IS 'Provenance of net_weight_g: measured (user weighed it), typical (catalogue median accepted), estimated (user guess).';



COMMENT ON COLUMN "public"."product_materials"."match_status" IS 'Emission factor provenance: verified (user picked/confirmed), auto_matched (software matched, awaiting confirmation), needs_review (no usable match). NULL = legacy row, unknown.';



COMMENT ON COLUMN "public"."product_materials"."openlca_no_match_at" IS 'When the openlca_no_match verdict was last confirmed by a live lookup. NULL or older than 90 days means the resolver will re-try a live OpenLCA calculation on the next recalculation and refresh/clear the flag based on the result.';



COMMENT ON CONSTRAINT "origin_coordinates_completeness" ON "public"."product_materials" IS 'Ensures origin_lat and origin_lng are either both NULL or both specified for valid geolocation data.';



COMMENT ON CONSTRAINT "product_materials_unit_check" ON "public"."product_materials" IS 'Units must come from the canonical vocabulary in lib/constants/material-units.ts. Unknown units are treated as kg by the LCA calculator, silently corrupting footprints.';



COMMENT ON CONSTRAINT "transport_data_completeness" ON "public"."product_materials" IS 'Ensures transport_mode and distance_km are either both NULL or both specified for data consistency.';



CREATE TABLE IF NOT EXISTS "public"."production_chain_templates" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "organization_id" "uuid",
    "kind" "text" NOT NULL,
    "name" "text" NOT NULL,
    "description" "text",
    "stages" "jsonb" NOT NULL,
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "production_chain_templates_kind_check" CHECK (("kind" = ANY (ARRAY['built_in'::"text", 'custom'::"text"]))),
    CONSTRAINT "production_chain_templates_org_required_for_custom" CHECK (((("kind" = 'built_in'::"text") AND ("organization_id" IS NULL)) OR (("kind" = 'custom'::"text") AND ("organization_id" IS NOT NULL))))
);


ALTER TABLE "public"."production_chain_templates" OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."production_run_resource_data" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "facility_id" "uuid" NOT NULL,
    "organization_id" "uuid" NOT NULL,
    "production_log_id" "uuid",
    "product_id" bigint NOT NULL,
    "production_date" "date" NOT NULL,
    "production_volume" numeric NOT NULL,
    "production_volume_unit" "text" DEFAULT 'Litres'::"text" NOT NULL,
    "units_produced" numeric,
    "electricity_total_kwh" numeric,
    "electricity_kwh_per_day" numeric,
    "production_days" numeric,
    "electricity_computed_kwh" numeric,
    "water_intake_m3" numeric,
    "wastewater_discharge_m3" numeric,
    "data_provenance" "text" DEFAULT 'primary_supplier_verified'::"text" NOT NULL,
    "verification_status" "text" DEFAULT 'unverified'::"text" NOT NULL,
    "notes" "text",
    "created_by" "uuid" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    CONSTRAINT "prrd_electricity_non_negative" CHECK (((("electricity_total_kwh" IS NULL) OR ("electricity_total_kwh" >= (0)::numeric)) AND (("electricity_kwh_per_day" IS NULL) OR ("electricity_kwh_per_day" >= (0)::numeric)) AND (("electricity_computed_kwh" IS NULL) OR ("electricity_computed_kwh" >= (0)::numeric)))),
    CONSTRAINT "prrd_positive_volume" CHECK (("production_volume" > (0)::numeric)),
    CONSTRAINT "prrd_provenance_check" CHECK (("data_provenance" = ANY (ARRAY['primary_supplier_verified'::"text", 'primary_measured_onsite'::"text", 'secondary_calculated_allocation'::"text", 'secondary_modelled_industry_average'::"text"]))),
