CREATE TABLE IF NOT EXISTS "public"."vineyard_growing_profiles" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "product_id" bigint,
    "vineyard_id" "uuid" NOT NULL,
    "organization_id" "uuid" NOT NULL,
    "vintage_year" integer DEFAULT EXTRACT(year FROM "now"()) NOT NULL,
    "area_ha" numeric(10,4) NOT NULL,
    "soil_management" "text" DEFAULT 'conventional_tillage'::"text" NOT NULL,
    "fertiliser_type" "text" DEFAULT 'none'::"text" NOT NULL,
    "fertiliser_quantity_kg" numeric(10,2) DEFAULT 0 NOT NULL,
    "fertiliser_n_content_percent" numeric(5,2) DEFAULT 0 NOT NULL,
    "uses_pesticides" boolean DEFAULT false NOT NULL,
    "pesticide_applications_per_year" integer DEFAULT 0 NOT NULL,
    "uses_herbicides" boolean DEFAULT false NOT NULL,
    "herbicide_applications_per_year" integer DEFAULT 0 NOT NULL,
    "diesel_litres_per_year" numeric(10,2) DEFAULT 0 NOT NULL,
    "petrol_litres_per_year" numeric(10,2) DEFAULT 0 NOT NULL,
    "is_irrigated" boolean DEFAULT false NOT NULL,
    "water_m3_per_ha" numeric(10,2) DEFAULT 0 NOT NULL,
    "irrigation_energy_source" "text" DEFAULT 'none'::"text" NOT NULL,
    "grape_yield_tonnes" numeric(10,2) NOT NULL,
    "soil_carbon_override_kg_co2e_per_ha" numeric,
    "soil_carbon_measurement_date" "date",
    "soil_carbon_methodology" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "pruning_residue_returned" boolean DEFAULT true,
    "pesticide_type" "text" DEFAULT 'generic'::"text",
    "herbicide_type" "text" DEFAULT 'generic'::"text",
    "soil_carbon_lab_name" "text",
    "soil_carbon_sampling_points" integer,
    "is_draft" boolean DEFAULT true NOT NULL,
    "land_ownership_type" "text",
    "lease_expiry_date" "date",
    "is_boundary_controlled" boolean DEFAULT true NOT NULL,
    "pruning_residue_management_type" "text" DEFAULT 'in_field'::"text",
    "pruning_residue_measured_kg_per_ha" numeric,
    "removal_verification_status" "text" DEFAULT 'unverified'::"text" NOT NULL,
    "removal_verifier_body" "text",
    "removal_verifier_standard" "text",
    "removal_verification_date" "date",
    "removal_verification_expiry" "date",
    "ecosystem_type" "text",
    "in_biodiversity_sensitive_area" boolean DEFAULT false NOT NULL,
    "sensitive_area_details" "text",
    "water_stress_index" "text",
    "pruning_residue_burned_kg_per_ha" numeric,
    "red_diesel_litres_per_year" numeric,
    CONSTRAINT "vineyard_growing_profiles_area_ha_check" CHECK (("area_ha" > (0)::numeric)),
    CONSTRAINT "vineyard_growing_profiles_diesel_litres_per_year_check" CHECK (("diesel_litres_per_year" >= (0)::numeric)),
    CONSTRAINT "vineyard_growing_profiles_ecosystem_type_check" CHECK (("ecosystem_type" = ANY (ARRAY['temperate_forest'::"text", 'mediterranean'::"text", 'grassland'::"text", 'wetland'::"text", 'shrubland'::"text", 'tropical_forest'::"text", 'boreal_forest'::"text", 'semi_arid'::"text", 'other'::"text"]))),
    CONSTRAINT "vineyard_growing_profiles_fertiliser_n_content_percent_check" CHECK ((("fertiliser_n_content_percent" >= (0)::numeric) AND ("fertiliser_n_content_percent" <= (100)::numeric))),
    CONSTRAINT "vineyard_growing_profiles_fertiliser_quantity_kg_check" CHECK (("fertiliser_quantity_kg" >= (0)::numeric)),
    CONSTRAINT "vineyard_growing_profiles_fertiliser_type_check" CHECK (("fertiliser_type" = ANY (ARRAY['none'::"text", 'synthetic_n'::"text", 'organic_manure'::"text", 'organic_compost'::"text", 'mixed'::"text"]))),
    CONSTRAINT "vineyard_growing_profiles_grape_yield_tonnes_check" CHECK (("grape_yield_tonnes" >= (0)::numeric)),
    CONSTRAINT "vineyard_growing_profiles_herbicide_applications_per_year_check" CHECK (("herbicide_applications_per_year" >= 0)),
    CONSTRAINT "vineyard_growing_profiles_irrigation_energy_source_check" CHECK (("irrigation_energy_source" = ANY (ARRAY['grid_electricity'::"text", 'diesel_pump'::"text", 'solar_pump'::"text", 'gravity_fed'::"text", 'none'::"text"]))),
    CONSTRAINT "vineyard_growing_profiles_land_ownership_type_check" CHECK (("land_ownership_type" = ANY (ARRAY['owned'::"text", 'leased'::"text", 'rental'::"text", 'contract_growing'::"text"]))),
    CONSTRAINT "vineyard_growing_profiles_pesticide_applications_per_year_check" CHECK (("pesticide_applications_per_year" >= 0)),
    CONSTRAINT "vineyard_growing_profiles_petrol_litres_per_year_check" CHECK (("petrol_litres_per_year" >= (0)::numeric)),
    CONSTRAINT "vineyard_growing_profiles_pruning_residue_burned_kg_per_h_check" CHECK (("pruning_residue_burned_kg_per_ha" > (0)::numeric)),
    CONSTRAINT "vineyard_growing_profiles_pruning_residue_management_type_check" CHECK (("pruning_residue_management_type" = ANY (ARRAY['in_field'::"text", 'removed_for_biomass'::"text", 'chipped_and_spread'::"text", 'burned'::"text"]))),
    CONSTRAINT "vineyard_growing_profiles_pruning_residue_measured_kg_per_check" CHECK (("pruning_residue_measured_kg_per_ha" > (0)::numeric)),
    CONSTRAINT "vineyard_growing_profiles_red_diesel_litres_per_year_check" CHECK ((("red_diesel_litres_per_year" IS NULL) OR ("red_diesel_litres_per_year" >= (0)::numeric))),
    CONSTRAINT "vineyard_growing_profiles_removal_verification_status_check" CHECK (("removal_verification_status" = ANY (ARRAY['unverified'::"text", 'pending'::"text", 'verified'::"text", 'rejected'::"text", 'expired'::"text"]))),
    CONSTRAINT "vineyard_growing_profiles_soil_management_check" CHECK (("soil_management" = ANY (ARRAY['conventional_tillage'::"text", 'minimum_tillage'::"text", 'no_till'::"text", 'cover_cropping'::"text", 'composting'::"text", 'biochar_compost'::"text", 'regenerative_integrated'::"text"]))),
    CONSTRAINT "vineyard_growing_profiles_water_m3_per_ha_check" CHECK (("water_m3_per_ha" >= (0)::numeric)),
    CONSTRAINT "vineyard_growing_profiles_water_stress_index_check" CHECK (("water_stress_index" = ANY (ARRAY['low'::"text", 'medium'::"text", 'high'::"text", 'very_high'::"text"])))
);


ALTER TABLE "public"."vineyard_growing_profiles" OWNER TO "postgres";


COMMENT ON COLUMN "public"."vineyard_growing_profiles"."land_ownership_type" IS 'GHG Protocol LSR v1.0 operational boundary definition';



COMMENT ON COLUMN "public"."vineyard_growing_profiles"."lease_expiry_date" IS 'Required if land_ownership_type is leased or rental';



COMMENT ON COLUMN "public"."vineyard_growing_profiles"."is_boundary_controlled" IS 'Whether the organisation controls land management decisions on this land';



COMMENT ON COLUMN "public"."vineyard_growing_profiles"."pruning_residue_management_type" IS 'How vine prunings are managed. in_field = left to decompose (default IPCC N2O applies). removed_for_biomass = N leaves system, zero N2O. chipped_and_spread = adjusted decomposition factor.';



COMMENT ON COLUMN "public"."vineyard_growing_profiles"."pruning_residue_measured_kg_per_ha" IS 'Measured dry matter from prunings in kg/ha/yr. If provided, overrides the VINE_PRUNING_DM_PER_HA default constant. Raises data quality to primary.';



COMMENT ON COLUMN "public"."vineyard_growing_profiles"."removal_verification_status" IS 'Third-party verification status for soil carbon removal claims';



COMMENT ON COLUMN "public"."vineyard_growing_profiles"."removal_verifier_body" IS 'Name of the third-party verification body (e.g. SCS Global Services, Verra)';



COMMENT ON COLUMN "public"."vineyard_growing_profiles"."removal_verifier_standard" IS 'Verification standard used (e.g. ISO 14064-3, Verra VCS, Gold Standard)';



COMMENT ON COLUMN "public"."vineyard_growing_profiles"."removal_verification_date" IS 'Date verification was completed';



COMMENT ON COLUMN "public"."vineyard_growing_profiles"."removal_verification_expiry" IS 'Date verification expires and re-verification is required';



COMMENT ON COLUMN "public"."vineyard_growing_profiles"."ecosystem_type" IS 'TNFD LEAP Locate phase: ecosystem type at the production location per IPBES categories.';



COMMENT ON COLUMN "public"."vineyard_growing_profiles"."in_biodiversity_sensitive_area" IS 'Whether the site is within or adjacent to a Key Biodiversity Area, UNESCO World Heritage Site, Ramsar wetland, or protected area.';



COMMENT ON COLUMN "public"."vineyard_growing_profiles"."sensitive_area_details" IS 'Name and designation of the biodiversity-sensitive area (if applicable).';



COMMENT ON COLUMN "public"."vineyard_growing_profiles"."water_stress_index" IS 'WRI Aqueduct or equivalent water stress classification for the location. Used for TNFD water dependency disclosure.';



COMMENT ON COLUMN "public"."vineyard_growing_profiles"."pruning_residue_burned_kg_per_ha" IS 'Dry matter of prunings burned in-field (kg/ha/yr). If NULL when management type = burned, the age-graduated VINE_PRUNING_DM_BY_AGE default is used. Drives IPCC 2006 Vol 4 Ch 2.4 field-burning CH4/N2O (biogenic CO2 excluded).';



COMMENT ON COLUMN "public"."vineyard_growing_profiles"."red_diesel_litres_per_year" IS 'Red / agricultural (gas oil) diesel for off-road vineyard machinery, litres/yr. Priced with DEFRA red-diesel factor (distinct from road diesel). NULL = none.';



