CREATE OR REPLACE VIEW "public"."waste_stream_summary" AS
 SELECT "fae"."organization_id",
    "fae"."facility_id",
    "f"."name" AS "facility_name",
    (EXTRACT(year FROM "fae"."activity_date"))::integer AS "year",
    (EXTRACT(month FROM "fae"."activity_date"))::integer AS "month",
    "fae"."waste_category",
    "fae"."waste_treatment_method",
    "fae"."hazard_classification",
    ("count"(*))::integer AS "entry_count",
    "sum"("fae"."quantity") AS "total_quantity_kg",
    "avg"("fae"."waste_recovery_percentage") AS "avg_recovery_percentage",
    "sum"("fae"."calculated_emissions_kg_co2e") AS "total_emissions_kg_co2e",
    "max"(("fae"."data_provenance")::"text") AS "data_provenance",
    "avg"("fae"."confidence_score") AS "avg_confidence_score"
   FROM ("public"."facility_activity_entries" "fae"
     JOIN "public"."facilities" "f" ON (("f"."id" = "fae"."facility_id")))
  WHERE (("fae"."activity_category" = ANY (ARRAY['waste_general'::"public"."facility_activity_category_enum", 'waste_hazardous'::"public"."facility_activity_category_enum", 'waste_recycling'::"public"."facility_activity_category_enum"])) AND ("fae"."waste_category" IS NOT NULL))
  GROUP BY "fae"."organization_id", "fae"."facility_id", "f"."name", (EXTRACT(year FROM "fae"."activity_date")), (EXTRACT(month FROM "fae"."activity_date")), "fae"."waste_category", "fae"."waste_treatment_method", "fae"."hazard_classification";


ALTER VIEW "public"."waste_stream_summary" OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."xero_account_mappings" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "organization_id" "uuid" NOT NULL,
    "xero_account_id" "text" NOT NULL,
    "xero_account_code" "text",
    "xero_account_name" "text" NOT NULL,
    "xero_account_type" "text",
    "emission_category" "text",
    "is_excluded" boolean DEFAULT false NOT NULL,
    "mapped_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


ALTER TABLE "public"."xero_account_mappings" OWNER TO "postgres";


COMMENT ON TABLE "public"."xero_account_mappings" IS 'Maps Xero chart-of-accounts entries to emission categories for transaction classification.';



COMMENT ON COLUMN "public"."xero_account_mappings"."emission_category" IS 'Emission category ID (e.g. grid_electricity, natural_gas, air_travel). NULL if unmapped.';



COMMENT ON COLUMN "public"."xero_account_mappings"."is_excluded" IS 'If true, transactions coded to this account are excluded from emission calculations.';



CREATE TABLE IF NOT EXISTS "public"."xero_connections" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "organization_id" "uuid" NOT NULL,
    "xero_tenant_id" "text" NOT NULL,
    "xero_tenant_name" "text",
    "access_token_encrypted" "text" NOT NULL,
    "refresh_token_encrypted" "text" NOT NULL,
    "token_expires_at" timestamp with time zone NOT NULL,
    "scopes" "text"[],
    "connected_by" "uuid",
    "connected_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "last_sync_at" timestamp with time zone,
    "sync_status" "text" DEFAULT 'idle'::"text" NOT NULL,
    "sync_error" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "xero_connections_sync_status_check" CHECK (("sync_status" = ANY (ARRAY['idle'::"text", 'syncing'::"text", 'error'::"text"])))
);


ALTER TABLE "public"."xero_connections" OWNER TO "postgres";


COMMENT ON TABLE "public"."xero_connections" IS 'Stores encrypted OAuth 2.0 tokens for Xero API connections. One row per organisation per connected Xero tenant.';



COMMENT ON COLUMN "public"."xero_connections"."access_token_encrypted" IS 'AES-256-GCM encrypted access token. Format: iv:authTag:ciphertext.';



COMMENT ON COLUMN "public"."xero_connections"."refresh_token_encrypted" IS 'AES-256-GCM encrypted refresh token. Each refresh issues a new token; always persist the latest.';



COMMENT ON COLUMN "public"."xero_connections"."sync_status" IS 'Current sync state: idle (ready), syncing (in progress), error (last sync failed).';



CREATE TABLE IF NOT EXISTS "public"."xero_supplier_links" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "organization_id" "uuid" NOT NULL,
    "xero_contact_id" "text" NOT NULL,
    "xero_contact_name" "text" NOT NULL,
    "supplier_id" "uuid",
    "match_type" "text" DEFAULT 'unmatched'::"text" NOT NULL,
    "match_confidence" numeric(3,2) DEFAULT 0,
    "total_spend" numeric DEFAULT 0,
    "transaction_count" integer DEFAULT 0,
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"(),
    CONSTRAINT "xero_supplier_links_confidence_check" CHECK ((("match_confidence" >= (0)::numeric) AND ("match_confidence" <= (1)::numeric))),
    CONSTRAINT "xero_supplier_links_match_type_check" CHECK (("match_type" = ANY (ARRAY['auto_exact'::"text", 'auto_fuzzy'::"text", 'manual'::"text", 'unmatched'::"text", 'ignored'::"text"])))
);


ALTER TABLE "public"."xero_supplier_links" OWNER TO "postgres";


