);


ALTER TABLE "public"."xero_supplier_rules" OWNER TO "postgres";


COMMENT ON TABLE "public"."xero_supplier_rules" IS 'Supplier name patterns mapped to emission categories. System defaults (organization_id IS NULL) apply to all orgs.';



COMMENT ON COLUMN "public"."xero_supplier_rules"."supplier_pattern" IS 'Case-insensitive ILIKE pattern (e.g. %british airways%).';



COMMENT ON COLUMN "public"."xero_supplier_rules"."priority" IS 'Higher values are checked first. Org-specific rules always take precedence over system defaults.';



CREATE TABLE IF NOT EXISTS "public"."xero_sync_logs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "organization_id" "uuid" NOT NULL,
    "sync_type" "text" NOT NULL,
    "status" "text" NOT NULL,
    "transactions_fetched" integer DEFAULT 0 NOT NULL,
    "transactions_classified" integer DEFAULT 0 NOT NULL,
    "accounts_fetched" integer DEFAULT 0 NOT NULL,
    "error_message" "text",
    "started_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "completed_at" timestamp with time zone,
    "triggered_by" "uuid",
    CONSTRAINT "xero_sync_logs_status_check" CHECK (("status" = ANY (ARRAY['started'::"text", 'completed'::"text", 'failed'::"text"]))),
    CONSTRAINT "xero_sync_logs_sync_type_check" CHECK (("sync_type" = ANY (ARRAY['full'::"text", 'incremental'::"text", 'accounts_only'::"text"])))
);


ALTER TABLE "public"."xero_sync_logs" OWNER TO "postgres";


COMMENT ON TABLE "public"."xero_sync_logs" IS 'Audit trail of Xero data synchronisation operations.';



CREATE TABLE IF NOT EXISTS "public"."xero_transactions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "organization_id" "uuid" NOT NULL,
    "xero_transaction_id" "text" NOT NULL,
    "xero_transaction_type" "text" NOT NULL,
    "xero_contact_name" "text",
    "xero_contact_id" "text",
    "xero_account_id" "text",
    "xero_account_code" "text",
    "description" "text",
    "amount" numeric NOT NULL,
    "currency" "text" DEFAULT 'GBP'::"text" NOT NULL,
    "transaction_date" "date" NOT NULL,
    "emission_category" "text",
    "classification_source" "text",
    "classification_confidence" numeric,
    "spend_based_emissions_kg" numeric,
    "data_quality_tier" integer DEFAULT 4 NOT NULL,
    "upgrade_status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "upgraded_entry_id" "uuid",
    "upgraded_entry_table" "text",
    "sync_batch_id" "uuid",
    "reporting_year" integer,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "extracted_metadata" "jsonb",
    "duplicate_flag" "text" DEFAULT 'none'::"text",
    "ai_suggested_category" "text",
    "ai_suggested_confidence" numeric,
    "ai_suggested_reasoning" "text",
    CONSTRAINT "xero_transactions_classification_confidence_check" CHECK ((("classification_confidence" >= (0)::numeric) AND ("classification_confidence" <= (1)::numeric))),
    CONSTRAINT "xero_transactions_classification_source_check" CHECK (("classification_source" = ANY (ARRAY['account_mapping'::"text", 'supplier_rule'::"text", 'manual'::"text", 'ai'::"text"]))),
    CONSTRAINT "xero_transactions_data_quality_tier_check" CHECK ((("data_quality_tier" >= 1) AND ("data_quality_tier" <= 4))),
    CONSTRAINT "xero_transactions_duplicate_flag_check" CHECK (("duplicate_flag" = ANY (ARRAY['none'::"text", 'probable_overlap'::"text", 'acknowledged'::"text"]))),
    CONSTRAINT "xero_transactions_upgrade_status_check" CHECK (("upgrade_status" = ANY (ARRAY['pending'::"text", 'upgraded'::"text", 'dismissed'::"text", 'not_applicable'::"text"]))),
    CONSTRAINT "xero_transactions_xero_transaction_type_check" CHECK (("xero_transaction_type" = ANY (ARRAY['invoice'::"text", 'bank_transaction'::"text", 'credit_note'::"text"])))
);


ALTER TABLE "public"."xero_transactions" OWNER TO "postgres";


COMMENT ON TABLE "public"."xero_transactions" IS 'Synced Xero transactions classified into emission categories with spend-based baselines and upgrade tracking.';



COMMENT ON COLUMN "public"."xero_transactions"."data_quality_tier" IS 'GHG Protocol data quality tier: 4=spend-based, 3=average/proxy, 2=activity-based, 1=supplier-specific.';



COMMENT ON COLUMN "public"."xero_transactions"."upgrade_status" IS 'Whether the user has provided higher-quality activity data: pending, upgraded, dismissed, or not_applicable.';



COMMENT ON COLUMN "public"."xero_transactions"."upgraded_entry_id" IS 'FK to the record created when the user upgrades (e.g. utility_data_entries.id).';



COMMENT ON COLUMN "public"."xero_transactions"."extracted_metadata" IS 'Auto-extracted data from invoice descriptions: airport codes, night counts, weights, quantities';



COMMENT ON COLUMN "public"."xero_transactions"."ai_suggested_category" IS 'AI-suggested emission category stored for manual review (confidence < 0.7)';



COMMENT ON COLUMN "public"."xero_transactions"."ai_suggested_confidence" IS 'Confidence score of the AI suggestion (0.0-1.0)';



COMMENT ON COLUMN "public"."xero_transactions"."ai_suggested_reasoning" IS 'AI reasoning for the suggestion, shown to user during review';



